content:
terraform {
  required_version = "~> 1.14"

  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 6.0"
    }
  }

  # Bootstrap intentionally uses local state — it manages the remote state bucket itself.
}

provider "aws" {
  region = var.aws_region

  default_tags {
    tags = merge(var.tags, {
      Project   = var.project_name
      ManagedBy = "Terraform"
      Module    = "bootstrap"
    })
  }
}

data "aws_caller_identity" "current" {}

# ── Remote state backend ──────────────────────────────────────────────────────

resource "aws_s3_bucket" "tf_state" {
  bucket        = "${var.project_name}-tfstate-${data.aws_caller_identity.current.account_id}"
  force_destroy = false
}

resource "aws_s3_bucket_versioning" "tf_state" {
  bucket = aws_s3_bucket.tf_state.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "tf_state" {
  bucket = aws_s3_bucket.tf_state.id
  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_s3_bucket_public_access_block" "tf_state" {
  bucket                  = aws_s3_bucket.tf_state.id
  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# ── GitHub Actions OIDC ───────────────────────────────────────────────────────
# Only one OIDC provider for token.actions.githubusercontent.com is allowed per
# AWS account. Set create_oidc_provider = false and run:
#   terraform import aws_iam_openid_connect_provider.github <existing-arn>
# if it already exists from another project.

resource "aws_iam_openid_connect_provider" "github" {
  count = var.create_oidc_provider ? 1 : 0

  url             = "https://token.actions.githubusercontent.com"
  client_id_list  = ["sts.amazonaws.com"]
  thumbprint_list = ["6938fd4d98bab03faadb97b34396831e3780aea1"]
}

data "aws_iam_openid_connect_provider" "github" {
  count = var.create_oidc_provider ? 0 : 1
  url   = "https://token.actions.githubusercontent.com"
}

locals {
  oidc_provider_arn = var.create_oidc_provider ? aws_iam_openid_connect_provider.github[0].arn : data.aws_iam_openid_connect_provider.github[0].arn
}

# ── IAM role assumed by GitHub Actions ───────────────────────────────────────

data "aws_iam_policy_document" "github_actions_assume" {
  statement {
    effect  = "Allow"
    actions = ["sts:AssumeRoleWithWebIdentity"]

    principals {
      type        = "Federated"
      identifiers = [local.oidc_provider_arn]
    }

    condition {
      test     = "StringEquals"
      variable = "token.actions.githubusercontent.com:aud"
      values   = ["sts.amazonaws.com"]
    }

    # Scoped to PRs, pushes to main, and environment-gated jobs (dev/prod).
    # The environment: condition enables the GitHub approval gate — when a job
    # has environment: prod the OIDC sub becomes repo:ORG/REPO:environment:prod.
    condition {
      test     = "StringLike"
      variable = "token.actions.githubusercontent.com:sub"
      values = [
        "repo:${var.github_org}/${var.github_repo}:pull_request",
        "repo:${var.github_org}/${var.github_repo}:ref:refs/heads/main",
        "repo:${var.github_org}/${var.github_repo}:environment:dev",
        "repo:${var.github_org}/${var.github_repo}:environment:prod",
      ]
    }
  }
}

resource "aws_iam_role" "github_actions" {
  name                 = "${var.project_name}-github-actions"
  description          = "Assumed by GitHub Actions via OIDC to deploy ${var.project_name}"
  assume_role_policy   = data.aws_iam_policy_document.github_actions_assume.json
  max_session_duration = 3600
}

# AdministratorAccess is broad — scope this down to only the services your
# project actually needs once you know what you're deploying.
resource "aws_iam_role_policy_attachment" "github_actions_admin" {
  role       = aws_iam_role.github_actions.name
  policy_arn = "arn:aws:iam::aws:policy/AdministratorAccess"
}

data "aws_iam_policy_document" "aws_trust_policy" {
  statement {
    sid = var.statement_id
    actions = ["sts:AssumeRole"]

    principals {
      type        = var.trusted_identifier.type
      identifiers = var.trusted_identifier.identifiers
    }

    dynamic "condition" {
      for_each = var.conditions
      content {
        test     = lookup(condition.value.condition, "test", null)
        variable = lookup(condition.value.condition, "variable", null)
        values   = lookup(condition.value.condition, "values", null)
      }
    }
  }
}

resource "aws_iam_role" "role" {
  description           = var.description
  name                  = var.name
  assume_role_policy    = data.aws_iam_policy_document.aws_trust_policy.json
  managed_policy_arns   = var.managed_policy_arns
  force_detach_policies = true
}

/**
 * AWS IAM Role Terraform Module
 * =====================
 *
 * Usage:
 * ------
 *
 *     module "iam_role" {
 *       source      = "../tf_iam_role"
 *
 *       add variables
 *     }
**/

resource "aws_iam_role" "default_ecs_role" {
  #name = "ecs-role-${var.name}-${var.environment}"
  name = "${var.namespaced ? format("%s-%s-ecs-role", var.environment, var.name) : format("%s-ecs-role", var.name)}"

  assume_role_policy = <<EOF
{
  "Version": "2008-10-17",
  "Statement": [
    {
      "Action": "sts:AssumeRole",
      "Principal": {
        "Service": [
          "ecs.amazonaws.com",
          "ec2.amazonaws.com"
        ]
      },
      "Effect": "Allow"
    }
  ]
}
EOF
}

resource "aws_iam_role_policy" "default_ecs_service_role_policy" {
  #name = "ecs-service-role-policy-${var.name}-${var.environment}"
  name = "${var.namespaced ? format("%s-%s-ecs-service-role-policy", var.environment, var.name) : format("%s-ecs-service-role-policy", var.name)}"
  role = "${aws_iam_role.default_ecs_role.id}"

  policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Action": [
        "ec2:AuthorizeSecurityGroupIngress",
        "ec2:Describe*",
        "elasticloadbalancing:DeregisterInstancesFromLoadBalancer",
        "elasticloadbalancing:Describe*",
        "elasticloadbalancing:RegisterInstancesWithLoadBalancer"
      ],
      "Resource": "*"
    }
  ]
}
EOF
}

resource "aws_iam_role_policy" "default_ecs_instance_role_policy" {
  #name = "ecs-instance-role-policy-${var.name}-${var.environment}"
  name = "${var.namespaced ? format("%s-%s-ecs-instance-role-policy", var.environment, var.name) : format("%s-ecs-instance-role-policy", var.name)}"
  role = "${aws_iam_role.default_ecs_role.id}"

  policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Action": [
        "ecs:CreateCluster",
        "ecs:DeregisterContainerInstance",
        "ecs:DiscoverPollEndpoint",
        "ecs:Poll",
        "ecs:RegisterContainerInstance",
        "ecs:StartTelemetrySession",
        "ecs:Submit*",
        "ecr:GetAuthorizationToken",
        "ecr:BatchCheckLayerAvailability",
        "ecr:GetDownloadUrlForLayer",
        "ecr:BatchGetImage",
        "ecs:StartTask",
        "autoscaling:*"
      ],
      "Resource": "*"
    },
    {
      "Effect": "Allow",
      "Action": [
        "logs:CreateLogGroup",
        "logs:CreateLogStream",
        "logs:PutLogEvents",
        "logs:DescribeLogStreams"
      ],
      "Resource": "arn:aws:logs:*:*:*"
    }
  ]
}
EOF
}

resource "aws_iam_instance_profile" "default_ecs" {
  #name  = "ecs-instance-profile-${var.name}-${var.environment}"
  name = "${var.namespaced ? format("%s-%s-ecs-instance-profile", var.environment, var.name) : format("%s-ecs-instance-profile", var.name)}"
  path  = "/"
  role = "${aws_iam_role.default_ecs_role.name}"
}

resource "aws_iam_user" "this" {
  count = var.mode == "iam-user" ? 1 : 0
  name  = var.user_name
}

resource "aws_iam_role" "this" {
  count = var.mode == "iam-user" ? 1 : 0
  name  = var.role_name

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Effect = "Allow",
        Principal = {
          AWS = "arn:aws:iam::${var.account_id}:user/${var.user_name}"
        },
        Action = "sts:AssumeRole"
      }
    ]
  })
}

resource "aws_iam_user_policy" "assume_role" {
  count = var.mode == "iam-user" ? 1 : 0
  name  = "${var.user_name}-assume-role"
  user  = aws_iam_user.this[0].name

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Effect   = "Allow",
        Action   = "sts:AssumeRole",
        Resource = aws_iam_role.this[0].arn
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "billing_readonly" {
  count      = var.mode == "iam-user" ? 1 : 0
  role       = aws_iam_role.this[0].name
  policy_arn = "arn:aws:iam::aws:policy/job-function/Billing"
}

resource "aws_iam_role_policy_attachment" "cloudwatch_readonly" {
  count      = var.mode == "iam-user" ? 1 : 0
  role       = aws_iam_role.this[0].name
  policy_arn = "arn:aws:iam::aws:policy/CloudWatchReadOnlyAccess"
}

resource "aws_iam_role_policy_attachment" "organizations_readonly" {
  count      = var.attach_organizations_policy && var.mode == "iam-user" ? 1 : 0
  role       = aws_iam_role.this[0].name
  policy_arn = "arn:aws:iam::aws:policy/AWSOrganizationsReadOnlyAccess"
}

resource "aws_iam_role" "role" {
  name               = var.name
  description        = var.description
  assume_role_policy = data.aws_iam_policy_document.account_assume_role.json
}

data "aws_iam_policy_document" "account_assume_role" {
  statement {
    actions = [
      "sts:AssumeRole"
    ]
    principals {
      type        = "AWS"
      identifiers = [
      for account_id in var.account_ids :
      // Specifying the root account is the same as just using the account id but this is what
      // we get from using the console so use this format so that it doesn't cause a change.
      "arn:aws:iam::${account_id}:root"
      ]
    }
    condition {
      test     = "BoolIfExists"
      variable = "aws:MultiFactorAuthPresent"
      values   = [
        "true"
      ]
    }
  }
}

resource "aws_iam_policy" "assume_role" {
  name        = "${var.name}AssumeRole"
  description = "Assume the ${var.name} role."
  policy      = data.aws_iam_policy_document.assume_role.json
}

data "aws_iam_policy_document" "assume_role" {
  statement {
    actions   = [
      "sts:AssumeRole"
    ]
    resources = [
      aws_iam_role.role.arn
    ]
  }
}

resource "aws_iam_group_policy_attachment" "assume_role" {
  for_each   = var.groups
  group      = each.value
  policy_arn = aws_iam_policy.assume_role.arn
}

resource "aws_iam_role_policy_attachment" "policy" {
  for_each   = var.policies
  role       = aws_iam_role.role.name
  policy_arn = each.value
}

module "amplify_role" {
  source  = "BotTech/role/aws"
  version = "1.0.0"

  account_ids = [
    data.aws_caller_identity.current.account_id
  ]
  description = "Provides developer access to Amplify resources."
  groups      = [
    var.group
  ]
  name        = "Developer"
  policies    = {
    resources = aws_iam_policy.amplify_developer.arn
    ecr       = "arn:aws:iam::aws:policy/AmazonEC2ContainerRegistryPowerUser"
  }
}

data "aws_caller_identity" "current" {}

resource "aws_iam_policy" "amplify_developer" {
  description = "Allow a user to develop applications using AWS Amplify."
  name        = "AWSAmplifyDeveloper"
  policy      = data.aws_iam_policy_document.amplify_developer.json
}

data "aws_iam_policy_document" "amplify_developer" {
  statement {
    sid       = "AmplifyFullAccess"
    actions   = [
      "amplify:*",
      "apigateway:*",
      "appsync:*",
      "cloudformation:*",
      "cognito-identity:*",
      "cognito-idp:*",
      "dynamodb:*",
      "iam:*",
      "lambda:*",
      "route53:*",
      "s3:*"
    ]
    resources = [
      "*"
    ]
  }
}

module "billing_role" {
  source  = "BotTech/role/aws"
  version = "1.0.0"

  account_ids = [
    data.aws_caller_identity.current.account_id
  ]
  description = "Provides access to billing information."
  groups      = [
    var.group
  ]
  name        = "Billing"
  policies    = {
    billing       = "arn:aws:iam::aws:policy/job-function/Billing"
    notifications = aws_iam_policy.subscribe_to_billing_notifications.arn
  }
}

data "aws_caller_identity" "current" {}

resource "aws_iam_policy" "subscribe_to_billing_notifications" {
  name        = "SubscribeToBillingNotifications"
  description = "Allow a user to manage their subscription to billing notifications."
  policy      = data.aws_iam_policy_document.subscribe_to_billing_notifications.json
}

data "aws_iam_policy_document" "subscribe_to_billing_notifications" {
  statement {
    actions   = [
      "sns:ConfirmSubscription",
      "sns:GetTopicAttributes",
      "sns:Subscribe"
    ]
    resources = [
      var.notifications_topic_arn
    ]
  }
  statement {
    actions   = [
      "sns:ListTopics"
    ]
    resources = [
      "*"
    ]
  }
}

data "aws_iam_policy_document" "assume_role_policy" {

  statement {

    actions = ["sts:AssumeRole"]

    principals {
      type        = "AWS"
      identifiers = ["${local.trusted_account_arns}"]
    }

    condition {
      test     = "Bool"
      values   = ["${local.mfa}"]
      variable = "aws:MultiFactorAuthPresent"
    }

  }

}

resource "aws_iam_role" "admin" {
  name               = "${local.role_name}"
  assume_role_policy = "${data.aws_iam_policy_document.assume_role_policy.json}"
}

resource "aws_iam_role_policy_attachment" "admin_policy" {
  role       = "${aws_iam_role.admin.name}"
  policy_arn = "${local.policy_arn}"
}

data "aws_iam_policy_document" "administrator" {
  statement {
    sid = "AllowFullAccessForIAMAccountsAndOrgs"
    actions = [
      "iam:*",
      "organizations:*",
      "account:*",
    ]
    resources = ["*"]
  }
}

resource "aws_iam_policy" "administrator" {
  name   = var.administrator-role-name
  path   = "/${var.org}/"
  policy = data.aws_iam_policy_document.administrator.json
}

resource "aws_iam_role_policy_attachment" "administrator" {
  policy_arn = aws_iam_policy.administrator.arn
  role = aws_iam_role.administrator.id
}
resource "aws_iam_role" "administrator" {
  name = var.administrator-role-name
  path                  = "/${var.org}/"
  max_session_duration  = local.max_session_duration
  description           = "Administrator Role"
  assume_role_policy = data.aws_iam_policy_document.administrator-assume-role-policy.json
  force_detach_policies = true
}

data "aws_iam_policy_document" "administrator-assume-role-policy" {
  statement {
    actions = [
      "sts:AssumeRole",
    ]

    principals {
      type        = "AWS"
      identifiers = var.administrator-trusted-entities
    }

    condition {
      variable = "aws:MultiFactorAuthPresent"
      test     = "Bool"
      values   = ["true"]
    }

    condition {
      variable = "aws:MultiFactorAuthAge"
      test     = "NumericLessThanEquals"
      values   = [local.max_session_duration]
    }
  }
}

resource "aws_iam_role" "developer" {
  name                  = var.developer-role-name
  path                  = "/${var.org}/"
  max_session_duration  = local.max_session_duration
  description           = "Developer Role"
  assume_role_policy    = data.aws_iam_policy_document.developer-assume-role-policy.json
  force_detach_policies = true
}

data "aws_iam_policy_document" "developer-assume-role-policy" {
  statement {
    actions = [
      "sts:AssumeRole",
    ]

    principals {
      type        = "AWS"
      identifiers = var.developer-trusted-entities
    }

    condition {
      variable = "aws:MultiFactorAuthPresent"
      test     = "Bool"
      values   = ["true"]
    }

    condition {
      variable = "aws:MultiFactorAuthAge"
      test     = "NumericLessThanEquals"
      values   = [local.max_session_duration]
    }
  }
}

resource "aws_iam_role_policy_attachment" "power-user" {
  policy_arn = "arn:aws:iam::aws:policy/PowerUserAccess"
  role       = aws_iam_role.developer.name
}

resource "aws_iam_role_policy_attachment" "eks-cluster-policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSClusterPolicy"
  role       = aws_iam_role.developer.name
}

resource "aws_iam_role_policy_attachment" "eks-service-policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSServicePolicy"
  role       = aws_iam_role.developer.name
}

resource "aws_iam_role_policy_attachment" "systems-manager" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonSSMFullAccess"
  role       = aws_iam_role.developer.name
}

resource "aws_iam_role_policy_attachment" "iam" {
  policy_arn = aws_iam_policy.iam.arn
  role       = aws_iam_role.developer.name
}

resource "aws_iam_policy" "iam" {
  name   = var.developer-role-name
  path   = "/${var.org}/"
  policy = data.aws_iam_policy_document.developer-iam.json
}

data "aws_iam_policy_document" "developer-iam" {
  statement {
    sid     = "DenyEverythingInOrgPath"
    effect  = "Deny"
    actions = ["*"]
    resources = [
      "arn:aws:iam::*:group/${var.org}/*",
      "arn:aws:iam::*:instance-profile/${var.org}/*",
      "arn:aws:iam::*:policy/${var.org}/*",
      "arn:aws:iam::*:role/${var.org}/*",
      "arn:aws:iam::*:user/${var.org}/*",
    ]
  }

  statement {
    sid = "AllowManagingRolesWithBoundary"
    actions = [
      "iam:AttachRolePolicy",
      "iam:CreateRole",
      "iam:DeleteRolePolicy",
      "iam:DetachRolePolicy",
      "iam:PutRolePermissionsBoundary",
      "iam:PutRolePolicy",
    ]
    resources = [
      "*"
    ]
    condition {
      variable = "iam:PermissionsBoundary"
      test     = "ForAnyValue:StringEquals"
      values = [
        aws_iam_policy.boundary.arn
      ]
    }
  }

  statement {
    sid = "AllowManagingRoles"
    actions = [
      "iam:DeleteRole",
      "iam:GetRole",
      "iam:GetRolePolicy",
      "iam:ListAttachedRolePolicies",
      "iam:ListInstanceProfilesForRole",
      "iam:ListRolePolicies",
      "iam:ListRoleTags",
      "iam:ListRoles",
      "iam:PassRole",
      "iam:TagRole",
      "iam:UntagRole",
      "iam:UpdateAssumeRolePolicy",
      "iam:UpdateRole",
      "iam:UpdateRoleDescription",
    ]
    resources = [
      "*"
    ]
  }

  statement {
    sid = "AllowManagingGroups"
    actions = [
      "iam:GetGroup",
      "iam:GetGroupPolicy",
      "iam:DeleteGroup",
      "iam:DetachGroupPolicy",
      "iam:ListAttachedGroupPolicies",
      "iam:ListGroups",
      "iam:ListGroupPolicies",
      "iam:RemoveUserFromGroup"
    ]
    resources = [
      "*"
    ]
  }

  statement {
    sid = "AllowManagingUsersWithBoundary"
    actions = [
      "iam:AttachUserPolicy",
      "iam:CreateUser",
      "iam:DetachUserPolicy",
      "iam:PutUserPermissionsBoundary",
      "iam:PutUserPolicy"
    ]
    resources = [
      "*"
    ]
    condition {
      variable = "iam:PermissionsBoundary"
      test     = "ForAnyValue:StringEquals"
      values = [
        aws_iam_policy.boundary.arn
      ]
    }
  }

  statement {
    sid = "AllowManagingUsers"
    actions = [
      "iam:AddUserToGroup",
      "iam:CreateAccessKey",
      "iam:DeleteAccessKey",
      "iam:DeleteUser",
      "iam:GetUser",
      "iam:GetUserPolicy",
      "iam:ListAccessKeys",
      "iam:ListAttachedUserPolicies",
      "iam:ListGroupsForUser",
      "iam:ListUsers",
      "iam:ListUserPolicies",
      "iam:TagUser",
      "iam:UntagUser",
    ]
    resources = [
      "*"
    ]
  }

  statement {
    sid = "AllowManagingPolicies"
    actions = [
      "iam:CreatePolicy",
      "iam:CreatePolicyVersion",
      "iam:DeletePolicy",
      "iam:DeletePolicyVersion",
      "iam:GetPolicy",
      "iam:GetPolicyVersion",
      "iam:ListEntitiesForPolicy",
      "iam:ListPolicies",
      "iam:ListPolicyVersions",
      "iam:SetDefaultPolicyVersion",
    ]
    resources = [
      "*"
    ]
  }

  statement {
    sid = "AllowManagingInstanceProfiles"
    actions = [
      "iam:AddRoleToInstanceProfile",
      "iam:CreateInstanceProfile",
      "iam:DeleteInstanceProfile",
      "iam:GetInstanceProfile",
      "iam:ListInstanceProfiles",
      "iam:RemoveRoleFromInstanceProfile",
    ]
    resources = [
      "*"
    ]
  }

  statement {
    sid = "FederatedAccessThroughSAML"
    actions = [
      "iam:UpdateSAMLProvider",
      "iam:ListSAMLProviders",
      "iam:GetSAMLProvider",
      "iam:DeleteSAMLProvider",
      "iam:CreateSAMLProvider"
    ]
    resources = [
      "*"
    ]
  }
}

resource "aws_iam_policy" "boundary" {
  name   = "developer-boundary"
  path   = "/${var.org}/"
  policy = data.aws_iam_policy_document.boundary.json
}

data "aws_iam_policy_document" "boundary" {
  statement {
    sid = "AllowFullAccessExceptForAdministratorPermissions"
    not_actions = [
      "iam:*",
      "organizations:*",
      "account:*",
    ]
    resources = ["*"]
  }

  statement {
    sid = "AllowMinimalIamAccess"
    actions = [
      "iam:CreateServiceLinkedRole",
      "iam:DeleteServiceLinkedRole",
      "iam:ListAttachedRolePolicies", // Required for EKS
      "iam:ListRoles",
      "iam:PassRole", // Required for creating service-roles that assume instance roles
      "organizations:DescribeOrganization",
      "account:ListRegions",
    ]
    resources = ["*"]
  }
}

data "aws_iam_policy_document" "list-iam-users" {
  statement {
    effect = "Allow"

    actions = [
      "iam:GetAccountSummary",
      "iam:ListAccountAliases",
      "iam:ListGroupsForUser",
      "iam:ListUsers",
    ]

    resources = [
      "arn:aws:iam::${data.aws_caller_identity.current.account_id}:*",
    ]
  }

  statement {
    actions = ["iam:GetUser"]

    resources = [
      "arn:aws:iam::${data.aws_caller_identity.current.account_id}:user/$${aws:username}",
    ]

    effect = "Allow"
  }
}

resource "aws_iam_policy" "list-iam-users" {
  path        = "/"
  description = "Lets users see the list of users"

  policy = data.aws_iam_policy_document.list-iam-users.json
}


resource "aws_iam_user_policy_attachment" "list-iam-users" {
  user = aws_iam_user.this.id
  policy_arn = aws_iam_policy.list-iam-users.arn
}

data "aws_iam_policy_document" "access-key-self-service" {
  statement {
    actions = [
      "iam:CreateAccessKey",
      "iam:DeleteAccessKey",
      "iam:ListAccessKeys",
      "iam:UpdateAccessKey",
      "iam:GetAccessKeyLastUsed"
    ]

    effect = "Allow"

    condition {
      test     = "Bool"
      variable = "aws:MultiFactorAuthPresent"
      values   = ["true"]
    }

    condition {
      test     = "NumericLessThan"
      variable = "aws:MultiFactorAuthAge"
      values   = [local.max_session_duration]
    }

    resources = [
      "arn:aws:iam::${data.aws_caller_identity.current.account_id}:user/$${aws:username}",
    ]
  }
}

resource "aws_iam_policy" "aws_access_key_self_service" {
  path        = "/"
  description = "Policy for access key self service"

  policy = data.aws_iam_policy_document.access-key-self-service.json
}

resource "aws_iam_user_policy_attachment" "access-key-self-service" {
  user = aws_iam_user.this.id
  policy_arn = aws_iam_policy.aws_access_key_self_service.arn
}

data "aws_iam_policy_document" "manage-mfa" {
  statement {
    effect = "Allow"

    resources = [
      "arn:aws:iam::${data.aws_caller_identity.current.account_id}:user/$${aws:username}",
    ]

    actions = [
      "iam:DeactivateMFADevice",
      "iam:EnableMFADevice",
      "iam:ResyncMFADevice",
      "iam:ListVirtualMFADevices",
      "iam:ListMFADevices",
    ]
  }

  statement {
    effect = "Allow"

    resources = [
      "arn:aws:iam::${data.aws_caller_identity.current.account_id}:mfa/$${aws:username}",
    ]

    actions = [
      "iam:CreateVirtualMFADevice",
    ]
  }

  statement {
    effect = "Allow"

    resources = [
      "arn:aws:iam::${data.aws_caller_identity.current.account_id}:mfa/*",
    ]

    actions = [
      "iam:ListVirtualMFADevices",
      "iam:ListMFADevices",
    ]
  }
}

resource "aws_iam_policy" "aws_mfa_self_service" {
  path        = "/"
  description = "Policy for self-managing MFA"

  policy = data.aws_iam_policy_document.manage-mfa.json
}

resource "aws_iam_user_policy_attachment" "mfa-self-service" {
  user = aws_iam_user.this.id
  policy_arn = aws_iam_policy.aws_mfa_self_service.arn
}

## Get the current caller identity
data "aws_caller_identity" "current" {
}

## local variable to define the assumeRole policy to attach to the role
locals {
  aws_identifier = length(var.service_identifiers) > 0 && length(var.aws_identifiers) == 0 ? [] : [{
    type        = "AWS"
    identifiers = coalescelist(var.aws_identifiers, ["arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"])
  }]
  service_identifier = length(var.service_identifiers) == 0 ? [] : [{
    type        = "Service"
    identifiers = var.service_identifiers
  }]
}

# Generates an IAM policy document
data "aws_iam_policy_document" "iam_assumeRole_generic" {
  policy_id = "AssumeRole"
  statement {
    sid     = "AllowAssumeRole"
    actions = ["sts:AssumeRole"]
    dynamic "principals" {
      for_each = local.aws_identifier
      content {
        type        = principals.value["type"]
        identifiers = principals.value["identifiers"]
      }
    }
    dynamic "principals" {
      for_each = local.service_identifier
      content {
        type        = principals.value["type"]
        identifiers = principals.value["identifiers"]
      }
    }
    effect = "Allow"
  }
}

# Create the IAM role
resource "aws_iam_role" "role" {
  assume_role_policy    = coalesce(var.assume_role_policy, data.aws_iam_policy_document.iam_assumeRole_generic.json)
  description           = var.description
  force_detach_policies = var.force_detach_policies
  dynamic "inline_policy" {
    for_each = var.inline_policy
    content {
      name   = inline_policy.value["name"]
      policy = inline_policy.value["policy"]
    }
  }
  managed_policy_arns  = var.managed_policy_arns
  max_session_duration = var.max_session_duration
  name                 = var.name
  name_prefix          = var.name_prefix
  path                 = var.path
  permissions_boundary = var.permissions_boundary
  tags                 = var.tags
}

# Attach provided policies to the role
resource "aws_iam_role_policy_attachment" "role" {
  # The "for_each" value depends on resource attributes that cannot be determined
  # until apply, so Terraform cannot predict how many instances will be created.
  # for_each   = toset(var.policies)
  # policy_arn = each.key
  count      = var.policies_count
  role       = aws_iam_role.role.name
  policy_arn = element(var.policies, count.index)
}

# Attach provided inline policies to the role
resource "aws_iam_role_policy" "role" {
  # The "for_each" value depends on resource attributes that cannot be determined
  # until apply, so Terraform cannot predict how many instances will be created.
  # for_each = toset(var.json_policies)
  # policy   = each.key
  count  = var.json_policies_count
  role   = aws_iam_role.role.name
  name   = "${var.name}-${count.index}"
  policy = element(var.json_policies, count.index)
}

# Generates an IAM policy document
data "aws_iam_policy_document" "role_custom_assumeRole" {
  statement {
    sid     = "CustomAssumeRole"
    actions = ["sts:AssumeRole"]
    principals {
      type        = "Service"
      identifiers = ["ecs.amazonaws.com"]
    }
    effect = "Allow"
  }
}

module "role_custom_assumeRole" {
  source               = "JousP/iam-assumeRole/aws"
  version              = "~> 3.3"
  name                 = "custom-assumeRole"
  description          = "Custom role with customization the assume_role policy"
  assume_role_policy   = data.aws_iam_policy_document.role_custom_assumeRole.json
  path                 = "/custom/"
  max_session_duration = 7200
}

# Generates an IAM policy document
data "aws_iam_policy_document" "s3_all_readonly" {
  statement {
    actions   = ["s3:Get*", "s3:List*"]
    effect    = "Allow"
    resources = ["arn:aws:s3:::bucket1*"]
  }
}

data "aws_iam_policy_document" "s3_bucket3_readonly" {
  statement {
    actions   = ["s3:Get*", "s3:List*"]
    effect    = "Allow"
    resources = ["arn:aws:s3:::bucket3*"]
  }
}

data "aws_iam_policy_document" "s3_bucket4_readonly" {
  statement {
    actions   = ["s3:Get*", "s3:List*"]
    effect    = "Allow"
    resources = ["arn:aws:s3:::bucket4*"]
  }
}

resource "aws_iam_policy" "s3_all_readonly" {
  name        = "custom-policies-s3-all-readonly"
  path        = "/"
  description = "Policy for custom-policies role"
  policy      = data.aws_iam_policy_document.s3_all_readonly.json
}

module "role_custom_policies" {
  source              = "JousP/iam-assumeRole/aws"
  version             = "~> 3.3"
  name                = "custom-policies"
  description         = "Custom role with fixed inline and managed policies"
  path                = "/custom/"
  policies            = [aws_iam_policy.s3_all_readonly.arn]
  policies_count      = 1
  json_policies       = [data.aws_iam_policy_document.s3_bucket3_readonly.json]
  json_policies_count = 1
}

resource "aws_iam_role_policy" "role_custom_policies_bucket4" {
  name   = "custom-policies-s3-bucket4-readonly"
  role   = module.role_custom_policies.id
  policy = data.aws_iam_policy_document.s3_bucket4_readonly.json
}

resource "aws_iam_role_policy_attachment" "role_custom_policies_ro" {
  role       = module.role_custom_policies.id
  policy_arn = "arn:aws:iam::aws:policy/ReadOnlyAccess"
}

# Generates an IAM policy document
data "aws_iam_policy_document" "s3_bucket1_readonly" {
  statement {
    actions   = ["s3:Get*", "s3:List*"]
    effect    = "Allow"
    resources = ["arn:aws:s3:::bucket1*"]
  }
}

data "aws_iam_policy_document" "s3_bucket2_readonly" {
  statement {
    actions   = ["s3:Get*", "s3:List*"]
    effect    = "Allow"
    resources = ["arn:aws:s3:::bucket2*"]
  }
}

module "role_custom_policies_strict" {
  source              = "JousP/iam-assumeRole/aws"
  version             = "~> 3.3"
  name                = "custom-policies-trict"
  description         = "Custom role with fixed and strict inline and managed policies"
  path                = "/custom/"
  managed_policy_arns = ["arn:aws:iam::aws:policy/ReadOnlyAccess"]
  inline_policy = [
    {
      name   = "ReadOnlyBucket1"
      policy = data.aws_iam_policy_document.s3_bucket1_readonly.json
    },
    {
      name   = "ReadOnlyBucket2"
      policy = data.aws_iam_policy_document.s3_bucket2_readonly.json
    }
  ]
}

# Create an IAM role for the Lambda function
resource "aws_iam_role" "lambda_exec" {
  name = "lambda-exec-role-private-vpc-movie-search"

  assume_role_policy = jsonencode({
    Version   = "2012-10-17",
    Statement = [
      {
        Action    = "sts:AssumeRole",
        Effect    = "Allow",
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "lambda_mongodb_policy" {
  name = "lambda-mongodb-iam-policy"
  role = aws_iam_role.lambda_exec.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "sts:AssumeRole",
          "sts:TagSession"
        ]
        Resource = "*"
      }
    ]
  })
}

# Attach the AWSLambdaVPCAccessExecutionRole policy to the IAM role
resource "aws_iam_role_policy_attachment" "lambda_vpc_access" {
  role       = aws_iam_role.lambda_exec.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaVPCAccessExecutionRole"
}

# Create a security group for the Lambda function
resource "aws_security_group" "lambda_sg" {
  name        = "lambda-sg"
  description = "Security group for Lambda function"
  vpc_id      = aws_vpc.main.id

  # Allow all outbound traffic
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_s3_bucket" "lambda_deployment_bucket" {
  bucket_prefix = "lambda-code-movie-search-" # AWS recommends using a prefix for unique names

  # Enable versioning to easily revert to previous Lambda versions if needed

  tags = {
    Name = "Lambda Deployment Bucket for Movie Search"
  }
}

resource "aws_s3_object" "lambda_code_upload" {
  bucket = aws_s3_bucket.lambda_deployment_bucket.id
  # Use the MD5 hash of the zip file content as part of the key
  # This ensures a new S3 object is created if the code changes,
  # which properly triggers Lambda updates.
  key    = "lambda_function_package/${data.archive_file.lambda_zip.output_md5}.zip"
  source = data.archive_file.lambda_zip.output_path # Path to the generated zip file
  etag   = data.archive_file.lambda_zip.output_md5  # ETag for S3 object content verification
}

resource "aws_lambda_function" "my_lambda" {
  function_name = "get-movies" # Name for your Lambda function
  handler       = "lambda_function.lambda_handler" # File and function name
  runtime       = "python3.9"                      # Or python3.10, python3.11 etc.
  role          = aws_iam_role.lambda_exec.arn
  timeout       = 90                               # Lambda timeout in seconds (adjust as needed)
  memory_size   = 256                              # Lambda memory in MB (adjust as needed)

  s3_bucket = aws_s3_bucket.lambda_deployment_bucket.id
  # Updated: Reference the new aws_s3_object resource
  s3_key = aws_s3_object.lambda_code_upload.key

  # --- VPC Configuration ---
  # These must be IDs of existing resources in your AWS account.
  vpc_config {
    subnet_ids         = [aws_subnet.private_a.id, aws_subnet.private_b.id, aws_subnet.private_c.id]
    security_group_ids = [aws_security_group.lambda_sg.id]
  }

  # --- Environment Variables ---
  environment {
    variables = {
      MONGODB_URI = var.atlas_endpoint_service_name
      MONGODB_DATABASE = "sample_mflix"
      # Replace <user>, <password>, and the VPC endpoint DNS name with your actual values.
      # It's highly recommended to use AWS Secrets Manager for sensitive data like passwords.
    }
  }

  tags = {
    Name = "vector-search-lambda"
  }
}

data "aws_caller_identity" "current" {
}

module "iam_policy_document" {
  source         = "./iam-policy-document-abstraction"
  principal_arns = var.principal_arns
  require_mfa    = var.require_mfa
}

resource "aws_iam_role" "cross_account_assume_role" {
  name                 = var.role_name
  assume_role_policy   = module.iam_policy_document.iam_policy_json
  max_session_duration = var.max_session_duration
  tags                 = local.common_tags
}

resource "aws_iam_role_policy_attachment" "cross_account_assume_role" {
  count      = length(var.policy_arns)
  role       = aws_iam_role.cross_account_assume_role.name
  policy_arn = element(var.policy_arns, count.index)
}

output "iam_policy_json" {
  description = "Permissions attached to the policy"
  value = join(
    ",",
    concat(
      data.aws_iam_policy_document.cross_account_assume_role_policy[*].json,
      data.aws_iam_policy_document.cross_account_assume_role_policy_mfa[*].json,
    ),
  )
}

data "aws_iam_policy_document" "cross_account_assume_role_policy_mfa" {
  count = var.require_mfa ? 1 : 0

  statement {
    effect = "Allow"

    principals {
      type        = "AWS"
      identifiers = var.principal_arns
    }

    actions = ["sts:AssumeRole"]

    condition {
      test     = "Bool"
      variable = "aws:MultiFactorAuthPresent"
      values = [
        "true",
      ]
    }
  }
}

data "aws_iam_policy_document" "cross_account_assume_role_policy" {
  count = var.require_mfa ? 0 : 1

  statement {
    effect = "Allow"

    principals {
      type        = "AWS"
      identifiers = var.principal_arns
    }

    actions = ["sts:AssumeRole"]
  }
}

data "aws_iam_policy_document" "this" {
    dynamic "statement" {
        for_each = var.enabled_sts_services
        iterator = enabled_sts_services
        content {
            sid = "GrantSTS${upper(enabled_sts_services.value)}"
            actions = ["sts:AssumeRole"]
            principals {
                type        = "Service"
                identifiers = ["${enabled_sts_services.value}.amazonaws.com"]
            }
            effect = "Allow"
        }
    }
    statement {
        sid = "GrantK8sSAAccessToAWS"
        actions = ["sts:AssumeRoleWithWebIdentity"]
        principals {
            type        = "Federated"
            identifiers = [var.openid_connect_provider_arn]
        }
        effect = "Allow"    
        condition {
            test = "StringEquals"
            variable = "${replace(var.openid_connect_provider_url, "https://", "")}:sub"
            values = [
                "system:serviceaccount:${var.kubernetes_namespace}:${var.service_account_name}"
            ]
        }
        condition {
            test = "StringEquals"
            variable = "${replace(var.openid_connect_provider_url, "https://", "")}:aud"
            values = [
                "sts.amazonaws.com"
            ]
        }
    }
}

resource "aws_iam_role" "this" {
    name                = var.iam_role_name != "" ? var.iam_role_name : "${var.service_account_name}-role"
    assume_role_policy  = data.aws_iam_policy_document.this.json
}

resource "aws_iam_role_policy_attachment" "this" {
    count       = length(var.iam_policy_arns)
    role        = aws_iam_role.this.name
    policy_arn  = var.iam_policy_arns[count.index]
}

resource "kubernetes_service_account" "this" {
    count = var.provision_k8s_sa ? 1 : 0
    metadata {
        name        = var.service_account_name
        namespace   = var.kubernetes_namespace
        annotations = {
            "eks.amazonaws.com/role-arn" = aws_iam_role.this.arn
        }
    }
}

