resource "aws_ssm_activation" "this" {
  for_each = {
    for key in var.ssm_activations : key.name => {
      name               = key.name
      description        = key.description
      expiration_date    = key.expiration_date
      iam_role           = key.iam_role != null ? key.iam_role : (var.create_iam_role ? aws_iam_role.this[0].name : null)
      registration_limit = key.registration_limit
    }
  }
  name               = each.value.name
  description        = each.value.description
  expiration_date    = each.value.expiration_date
  iam_role           = each.value.iam_role
  registration_limit = each.value.registration_limit
  tags               = var.tags
}

resource "aws_iam_role" "this" {
  count = var.create_iam_role ? 1 : 0

  name = var.iam_role_name

  assume_role_policy = <<EOF
  {
    "Version": "2012-10-17",
    "Statement": {
      "Effect": "Allow",
      "Principal": {"Service": "ssm.amazonaws.com"},
      "Action": "sts:AssumeRole"
    }
  }
EOF
}

/**
 * ## Usage
 *
 * Creates an IAM Role for use as a Glue service role that can read from any bucket and use any KMS key.
 *
 * ```hcl
 * module "glue_iam_role" {
 *   source = "dod-iac/glue-iam-role/aws"
 *
 *   name = "glue-iam-role"
 *   buckets = ["*"]
 *   keys = ["*"]
 *   tags = {
 *     Automation  = "Terraform"
 *   }
 * }
 * ```
 *
 * Creates an IAM Role for use as a Glue service role that can read from a specific bucket and use any KMS key.
 *
 * ```hcl
 *
 * module "glue_iam_role" {
 *   source = "dod-iac/glue-iam-role/aws"
 *
 *   name = format("app-%s-glue-%s", var.application, var.environment)
 *   buckets = [aws_s3_bucket.main.arn]
 *   keys = ["*"]
 *   tags = {
 *     Application = var.application
 *     environment = var.environment
 *     Automation  = "Terraform"
 *   }
 * }
 * ```
 *
 * ## Terraform Version
 *
 * Terraform 0.13. Pin module version to ~> 1.0.0 . Submit pull-requests to master branch.
 *
 * Terraform 0.11 and 0.12 are not supported.
 *
 * ## License
 *
 * This project constitutes a work of the United States Government and is not subject to domestic copyright protection under 17 USC § 105.  However, because the project utilizes code licensed from contributors and other third parties, it therefore is licensed under the MIT License.  See LICENSE file for more information.
 */

data "aws_partition" "current" {}

data "aws_iam_policy_document" "assume_role_policy" {
  statement {
    effect  = "Allow"
    actions = ["sts:AssumeRole"]
    principals {
      type = "Service"
      identifiers = [
        "glue.amazonaws.com"
      ]
    }
  }
}

resource "aws_iam_role" "main" {
  name               = var.name
  description        = var.description
  assume_role_policy = length(var.assume_role_policy) > 0 ? var.assume_role_policy : data.aws_iam_policy_document.assume_role_policy.json
  tags               = var.tags
}

resource "aws_iam_role_policy_attachment" "aws_glue_service_role" {
  role       = aws_iam_role.main.name
  policy_arn = format("arn:%s:iam::aws:policy/service-role/AWSGlueServiceRole", data.aws_partition.current.partition)
}

data "aws_iam_policy_document" "main" {

  statement {
    sid = "ListBucket"
    actions = [
      "s3:GetBucketLocation",
      "s3:GetBucketRequestPayment",
      "s3:GetEncryptionConfiguration",
      "s3:ListBucket",
    ]
    effect    = length(var.buckets) > 0 ? "Allow" : "Deny"
    resources = length(var.buckets) > 0 ? var.buckets : ["*"]
  }

  statement {
    sid = "GetObject"
    actions = [
      "s3:GetObject",
    ]
    effect    = length(var.buckets) > 0 ? "Allow" : "Deny"
    resources = length(var.buckets) > 0 ? formatlist("%s/*", var.buckets) : ["*"]
  }

  statement {
    sid = "Decrypt"
    actions = [
      "kms:Decrypt",
    ]
    effect    = length(var.keys) > 0 ? "Allow" : "Deny"
    resources = length(var.keys) > 0 ? var.keys : ["*"]
  }

}

resource "aws_iam_policy" "main" {
  name        = length(var.policy_name) > 0 ? var.policy_name : format("%s-policy", var.name)
  description = length(var.policy_description) > 0 ? var.policy_description : format("The policy for %s.", var.name)
  policy      = data.aws_iam_policy_document.main.json
}

resource "aws_iam_role_policy_attachment" "main" {
  role       = aws_iam_role.main.name
  policy_arn = aws_iam_policy.main.arn
}

# iam.tf

# Trust policy: allow EC2 to assume this role
data "aws_iam_policy_document" "ec2_trust" {
  statement {
    actions = ["sts:AssumeRole"]
    principals {
      type        = "Service"
      identifiers = ["ec2.amazonaws.com"]
    }
  }
}

resource "aws_iam_role" "ec2" {
  name               = "${var.name_prefix}-role"
  assume_role_policy = data.aws_iam_policy_document.ec2_trust.json
  tags               = local.common_tags
}

# Attach SSM core so you can use Session Manager (no inbound SSH needed)
resource "aws_iam_role_policy_attachment" "ssm_core" {
  role       = aws_iam_role.ec2.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSSMManagedInstanceCore"
}


# Instance profile to attach the role to the EC2 instance
resource "aws_iam_instance_profile" "this" {
  name = "${var.name_prefix}-profile"
  role = aws_iam_role.ec2.name
  tags = local.common_tags
}

resource "aws_iam_instance_profile" "instance_role" {
  name = "${var.type}_${var.name}"
  role = aws_iam_role.iam_role.name
}

resource "aws_iam_role_policy" "role_policy" {
  name   = "${var.type}_${var.name}"
  role   = aws_iam_role.iam_role.id
  policy = var.policy_json
}

resource "aws_iam_role" "iam_role" {
  name = "${var.type}_${var.name}"

  assume_role_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Action": "sts:AssumeRole",
      "Principal": {
        "Service": "${var.type}.amazonaws.com"
      },
      "Effect": "Allow"
    }
  ]
}
EOF
}

resource "aws_iam_role" "this" {
  name               = "${var.role_name}"
  assume_role_policy = "${var.iam_role_policy_document_json}"
}

resource "aws_iam_role_policy_attachment" "attachment" {
  count      = "${var.policy_arns_count}"
  role       = "${aws_iam_role.this.name}"
  policy_arn = "${var.policy_arns[count.index]}"
}

resource "aws_iam_instance_profile" "instance_profile" {
  count = "${var.create_instance_role}"
  name  = "${aws_iam_role.this.name}"
  role  = "${aws_iam_role.this.name}"
}

variable "role_name" {
  description = "Role name"
}

variable "iam_role_policy_document_json" {
  type = "string"

  description = <<EOF
  Valid JSON Policy String
  this can be constructed from
  * terraform data.aws_iam_policy_document
  * terraform file provider
EOF
}

variable "policy_arns" {
  type        = "list"
  description = "List of policy arns to attach to this role"
  default     = []
}

variable "policy_arns_count" {
  description = "number of policy arns due to bug with length of computed value"
}

variable "create_instance_role" {
  description = "Need to create a same name instance role or not"
  default     = false
}

