provider "aws" {
  alias   = "source"
  profile = "source"
  region  = "us-east-2"
}

provider "aws" {
  alias   = "destination"
  profile = "destination"
  region  = "us-east-2"
}

data "aws_caller_identity" "source" {
  provider = aws.source
}

data "aws_iam_policy" "ec2" {
  provider = aws.destination
  name     = "AmazonEC2FullAccess"
}

data "aws_iam_policy_document" "assume_role" {
  provider = aws.destination
  statement {
    actions = [
      "sts:AssumeRole",
      "sts:TagSession",
      "sts:SetSourceIdentity"
    ]
    principals {
      type        = "AWS"
      identifiers = ["arn:aws:iam::${data.aws_caller_identity.source.account_id}:root"]
    }
  }
}

resource "aws_iam_role" "assume_role" {
  provider            = aws.destination
  name                = "assume_role"
  assume_role_policy  = data.aws_iam_policy_document.assume_role.json
  managed_policy_arns = [data.aws_iam_policy.ec2.arn]
  tags                = {}
}

resource "aws_iam_policy" "s3_management" {
  name = "s3_management"
  path = "/storage/"

  policy = <<-EOF
  {
    "Version": "2012-10-17",
    "Statement": [
      {
        "Action": [
          "s3:*"
        ],
        "Effect": "Allow",
        "Resource": "*"
      }
    ]
  }
  EOF
}

# 建立 instance profile，才能讓 IAM Role 套用在 EC2 instance 上
resource "aws_iam_instance_profile" "profile-robot" {
  name = "profile-robot"
  role = aws_iam_role.robot.name
}

# 若是想要接受特定 root user 下的所有 IAM User 都可以 AssumeRole
# Principal 的部份可以改成類似 => "AWS": "arn:aws:iam::777777777777:root"
resource "aws_iam_role" "robot" {
  name = "robot"

  assume_role_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Principal": {
        "Service": "ec2.amazonaws.com"
      },
      "Action": "sts:AssumeRole"
    }, 
    {
        "Effect": "Allow",
        "Principal": { 
            "AWS": "${aws_iam_user.robot.arn}"
        },
        "Action": "sts:AssumeRole",
        "Condition": {}
    }
  ]
}
EOF

  tags = {
    Name = "robot"
  }
}

resource "aws_iam_role_policy_attachment" "robot-s3_management" {
  role       = aws_iam_role.robot.name
  policy_arn = aws_iam_policy.s3_management.arn
}

resource "aws_iam_user" "robot" {
  name = "robot"
  path = "/auto/"

  tags = {
    Name = "robot"
  }
}

# 設定 AssumeRole 的 IAM Policy
# 讓 IAM User 可以切換到指定的 IAM Role
resource "aws_iam_user_policy" "assume_role-robot" {
  name = "assume_role-robot"
  user = aws_iam_user.robot.name

  policy = <<-EOF
  {
    "Version": "2012-10-17",
    "Statement": [
        {
            "Effect": "Allow",
            "Action": "sts:AssumeRole",
            "Resource": "${aws_iam_role.robot.arn}"
        }
    ]
  }
  EOF
}

resource "aws_iam_openid_connect_provider" "bitbucket" {
  client_id_list  = ["ari:cloud:bitbucket::workspace/${var.workspace_uuid}"]
  thumbprint_list = ["a031c46782e6e6c662c2c87c76da9aa62ccabd8e"]
  url             = "https://api.bitbucket.org/2.0/workspaces/${var.workspace_name}/pipelines-config/identity/oidc"
  tags            = var.tags
}

data "aws_iam_policy_document" "bitbucket_assume_role_policy" {
  for_each = var.roles
  statement {
    principals {
      identifiers = [aws_iam_openid_connect_provider.bitbucket.arn]
      type        = "Federated"
    }
    actions = ["sts:AssumeRoleWithWebIdentity"]
    condition {
      test     = "StringLike"
      variable = "api.bitbucket.org/2.0/workspaces/${var.workspace_name}/pipelines-config/identity/oidc:sub"
      values   = each.value.allowed_subjects
    }
  }
}

resource "aws_iam_role" "this" {
  for_each           = var.roles
  name               = each.value.name
  assume_role_policy = data.aws_iam_policy_document.bitbucket_assume_role_policy[each.key].json
  dynamic "inline_policy" {
    for_each = each.value.inline_policies_json
    content {
      name   = inline_policy.key
      policy = inline_policy.value
    }
  }

  tags = var.tags
}

data "aws_iam_policy_document" "pipeline_role" {
  statement {
    actions   = ["lambda:InvokeFunction", "logs:FilterLogEvents"]
    resources = ["*"]
  }
}

# Create the IAM provider with one role
module "bitbucket_oidc" {
  source = "../."

  workspace_name = "FaridN"
  workspace_uuid = "c95b4694-9b82-4fe5-9e2f-00ffac14cf93"
  #  You can get in the repository settings in the OpenID connect provider.

  roles = {
    role1 = {
      name                 = "BitbucketPipelineRepo1"
      allowed_subjects     = ["{573817ba-2f91-4ae3-8384-ff2cbc4caaa1}*"]
      inline_policies_json = [data.aws_iam_policy_document.pipeline_role.json]
    }
  }

  tags = {
    exampleTag = "exampleValue"
  }
}

output "role_arn" {
  description = "Use this as AWS_ROLE_ARN environmental variable in your pipeline."
  value       = module.bitbucket_oidc.roles.role1.arn
}

resource "aws_iam_role" "service_groups" {
  for_each = var.service_groups

  name_prefix          = "${var.role_name_prefix}${each.key}"
  path                 = var.role_path
  max_session_duration = var.role_max_session_duration
  tags = merge(
    var.tags,
    var.service_group_tag_key != null ? { "${var.service_group_tag_key}" : each.key } : {},
  )

  assume_role_policy = jsonencode({
    "Version" : "2012-10-17",
    "Statement" : {
      "Effect" : "Allow",
      "Principal" : {
        "Service" : sort(each.value),
      },
      "Action" : "sts:AssumeRole",
    },
  })
}

resource "aws_iam_role" "KP1ConsumerRole" {
  name = "KP1ConsumerRole"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      },
    ]
  })

  managed_policy_arns = [
    "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
  ]
}

resource "aws_iam_role_policy" "KP1ConsumerPolicy" {
  name   = "KP1ConsumerPolicy"
  role   = aws_iam_role.KP1ConsumerRole.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kinesis:DescribeStream",
          "kinesis:DescribeStreamSummary",
          "kinesis:GetRecords",
          "kinesis:GetShardIterator",
          "kinesis:ListShards",
          "kinesis:ListStreams",
          "kinesis:SubscribeToShard"
        ]
        Resource = aws_kinesis_stream.KP1DataStream.arn
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:DeleteObject",
          "s3:ListBucket"
        ]
        Resource = [
          "${aws_s3_bucket.KP1DataBucket.arn}",
          "${aws_s3_bucket.KP1DataBucket.arn}/*"
        ]
      },
    ]
  })
}

data "aws_caller_identity" "current" {}

data "aws_iam_policy_document" "assume_role_policy" {
  statement {
    actions = ["sts:AssumeRoleWithWebIdentity"]

    principals {
      type        = "Federated"
      identifiers = ["arn:aws:iam::${data.aws_caller_identity.current.account_id}:oidc-provider/token.actions.githubusercontent.com"]
    }
    condition {
      test     = "StringEquals"
      variable = "token.actions.githubusercontent.com:aud"
      values   = ["sts.amazonaws.com"]
    }
    condition {
      test     = var.condition_test
      variable = "token.actions.githubusercontent.com:sub"
      values   = length(var.assume_role_policy_condition_values) > 0 ? var.assume_role_policy_condition_values : ["repo:${var.org_name}/${var.repo_path}:ref:refs/heads/${var.ref}"]
    }
  }
}

resource "aws_iam_policy" "policy" {
  count = length(var.actions) > 0 ? 1 : 0
  name  = "${var.name}-policy"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action   = var.actions
        Effect   = "Allow"
        Resource = "*"
      },
    ]
  })
}

resource "aws_iam_role" "role" {
  name                = var.name
  assume_role_policy  = data.aws_iam_policy_document.assume_role_policy.json
  managed_policy_arns = length(var.actions) > 0 || length(var.managed_policy_arns) > 0 ? concat(var.managed_policy_arns, flatten(aws_iam_policy.policy[*].arn)) : []
}

locals {
  resources = formatlist("%s/%s/*", var.bucket_arn, var.services)
}

data "aws_iam_policy_document" "resource_readonly_access" {
  statement {
    sid    = "ReadonlyAccess"
    effect = "Allow"

    resources = local.resources

    actions = [
      "s3:GetObject",
      "s3:ListBucket",
      "s3:ListBucketMultipartUploads",
      "s3:GetBucketLocation",
      "s3:AbortMultipartUpload"
    ]
  }
}

data "aws_iam_policy_document" "resource_full_access" {
  statement {
    sid    = "FullAccess"
    effect = "Allow"

    resources = local.resources

    actions = [
      "s3:PutObject",
      "s3:PutObjectAcl",
      "s3:GetObject",
      "s3:DeleteObject",
      "s3:ListBucket",
      "s3:ListBucketMultipartUploads",
      "s3:GetBucketLocation",
      "s3:AbortMultipartUpload"
    ]
  }
}

data "aws_iam_policy_document" "base" {
  statement {
    sid    = "BaseAccess"
    effect = "Allow"

    resources = [
      var.bucket_arn
    ]

    actions = [
      "s3:ListBucket",
      "s3:ListBucketVersions"
    ]
  }
}

module "role" {
  source  = "cloudposse/iam-role/aws"
  version = "0.13.0"

  enabled = module.this.enabled && var.role_enabled ? true : false

  principals = {
    "AWS" : var.principals_arns
  }

  policy_documents = [
    var.read_only ? data.aws_iam_policy_document.resource_readonly_access.json : data.aws_iam_policy_document.resource_full_access.json,
    data.aws_iam_policy_document.base.json
  ]

  max_session_duration = var.max_session_duration
  role_description     = var.role_description
  policy_description   = var.policy_description

  context = module.this.context
}

