data "aws_iam_policy_document" "defaul_mfa_policy_document" {
    statement {
        effect  = "Allow"
        actions = [
            "iam:CreateVirtualMFADevice",
        ]

        resources = [
            "arn:aws:iam::${local.account_id}:mfa/$${aws:username}",
        ]
    }

    statement {
        effect  = "Allow"
        actions = [
            "iam:EnableMFADevice",
            "iam:GetUser",
            "iam:ListGroupsForUser",
            "iam:ListVirtualMFADevices",
        ]

        resources = [
            "arn:aws:iam::${local.account_id}:user/$${aws:username}",
        ]
    }

    statement {
        effect  = "Allow"
        actions = [
            "iam:ListMFADevices",
            "iam:ListVirtualMFADevices",
            "iam:ListUsers"
        ]

        resources = [
            "arn:aws:iam::${local.account_id}:user/",
            "arn:aws:iam::${local.account_id}:mfa/",
        ]
    }

		statement {
        effect    = "Allow"
        actions   = [
            "iam:ChangePassword",
            "iam:CreateAccessKey",
            "iam:DeleteAccessKey",
            "iam:ResyncMFADevice",
            "iam:UpdateAccessKey",
            "iam:UpdateUser",
        ]

        resources = [
            "arn:aws:iam::${local.account_id}:user/$${aws:username}",
        ]
    }
}

resource "aws_iam_policy" "defaul_mfa_policy_document" {
  name        = "default-mfa-policy"
  description = "Policy to allow MFA management for itself"
  policy      = "${data.aws_iam_policy_document.defaul_mfa_policy_document.json}"
}

resource "aws_iam_group_policy_attachment" "test-attach" {
  count      = "${length(local.groups)}"
  group      = "${element(local.groups, count.index)}"
  policy_arn = "${aws_iam_policy.defaul_mfa_policy_document.arn}"
}

data "aws_iam_policy_document" "assume_role_policy" {
  statement {
    effect = "Allow"

    actions = [
      "sts:AssumeRole",
    ]

    principals {
      type = "AWS"

      identifiers = [
        "arn:aws:iam::${local.account_id}:root",
      ]
    }

    condition {
      test     = "Bool"
      variable = "aws:MultiFactorAuthPresent"

      values = [
        "true",
      ]
    }

    condition {
      test     = "StringEquals"
      variable = "aws:PrincipalType"

      values = [
        "User",
      ]
    }
  }
}

# Roles and Groups to attach
resource "aws_iam_group_policy" "iamadmin" {
  name  = "iamadmin-group-policy"
  group = "${aws_iam_group.iamadmin.id}"

  policy = "${data.aws_iam_policy_document.iamadmin_group_assume.json}"
	depends_on = ["aws_iam_group.iamadmin"]
}

resource "aws_iam_role" "iamadmin" {
  name               = "iamadmin-role"
  description        = "The role to be assumed by the IAM Admin"
  assume_role_policy = "${data.aws_iam_policy_document.assume_role_policy.json}"

  tags = {
    Description = "IAM Admin with access to related policies"
  }
}

data "aws_iam_policy_document" "iamadmin_group_assume" {
  statement {
    effect = "Allow"

    actions = [
      "sts:AssumeRole",
    ]

    resources = [
      "${aws_iam_role.iamadmin.arn}",
    ]
  }
}

# Policies
resource "aws_iam_policy" "iamadmin" {
  name        = "iamadmin-security-policy"
  description = "IAM ADmin Security policy"
  path        = "/"
  policy      = "${file("${path.module}/policy/iamadmin/main.json")}"
}

resource "aws_iam_role_policy_attachment" "iamadmin_main" {
  role       = "${aws_iam_role.iamadmin.name}"
  policy_arn = "${aws_iam_policy.iamadmin.arn}"
}

####################
## OpenID Connect ##
####################
data "tls_certificate" "main" {
  url = data.terraform_remote_state.eks_cluster.outputs.eks_oidc
}

resource "aws_iam_openid_connect_provider" "main" {
  url = data.terraform_remote_state.eks_cluster.outputs.eks_oidc

  client_id_list = [
    "sts.amazonaws.com",
  ]

  thumbprint_list = [
    data.tls_certificate.main.certificates.0.sha1_fingerprint
  ]
}

################
## IAM Policy ##
################
resource "aws_iam_policy" "main" {
  name        = var.policy_name
  path        = "/"
  description = "Allow AWS EKS PODs to get a specify S3 Object"

  policy = file("${path.module}/policies/s3_policy.json")
}

resource "aws_iam_role" "main" {
  name                  = var.role_name
  path                  = "/"
  assume_role_policy    = data.template_file.role_trust_relationship.rendered
  force_detach_policies = false
}

resource "aws_iam_role_policy_attachment" "main" {
  role       = aws_iam_role.main.name
  policy_arn = aws_iam_policy.main.arn
}

############
## K8s SA ##
############
resource "kubernetes_service_account" "main" {
  metadata {
    name      = var.role_name
    namespace = "matheus"
    annotations = {
      "eks.amazonaws.com/role-arn" = aws_iam_role.main.arn
    }
  }
  automount_service_account_token = true
}

resource "aws_iam_role" "lambda_role" {
  count              = var.create_lambda_role ? 1 : 0
  name               = var.lambda_role_name
  assume_role_policy = file(var.lambda_policy_file) #file("modules/policies/lambda_policy.json")
}

// Role

resource "aws_iam_role" "admin-role" {
  assume_role_policy = "${data.aws_iam_policy_document.assume-from-mfa.json}"
  name               = "admin-role"
}

resource "aws_iam_role_policy_attachment" "admin-role-grants" {
  role       = "${aws_iam_role.admin-role.name}"
  policy_arn = "arn:aws:iam::aws:policy/AdministratorAccess"
}

// A policy we'll attach to selected groups to allow them using this role

data "aws_iam_policy_document" "assume-admin-role" {
  statement {
    sid       = "TfCustomPolicyAssumeAdminRole"
    effect    = "Allow"
    actions   = ["sts:AssumeRole"]
    resources = ["${aws_iam_role.admin-role.arn}"]
  }
}

resource "aws_iam_policy" "assume-admin-role" {
  name        = "tf-assume-admin-role"
  description = "Allow to assume the admin-role"
  policy      = "${data.aws_iam_policy_document.assume-admin-role.json}"
}

// Groups bindings

resource "aws_iam_group_policy_attachment" "attach-admin-to-admin-group" {
  group      = "${aws_iam_group.admin-group.name}"
  policy_arn = "${aws_iam_policy.assume-admin-role.arn}"
}

// Role

resource "aws_iam_role" "readonly-role" {
  assume_role_policy = "${data.aws_iam_policy_document.assume-from-mfa.json}"
  name               = "readonly-role"
}

resource "aws_iam_role_policy_attachment" "readonly-role-grants" {
  role       = "${aws_iam_role.readonly-role.name}"
  policy_arn = "arn:aws:iam::aws:policy/ReadOnlyAccess"
}

// A policy we'll attach to selected groups to allow them using this role

data "aws_iam_policy_document" "assume-readonly-role" {
  statement {
    sid       = "TfCustomPolicyAssumeReadOnlyRole"
    effect    = "Allow"
    actions   = ["sts:AssumeRole"]
    resources = ["${aws_iam_role.readonly-role.arn}"]
  }
}

resource "aws_iam_policy" "assume-readonly-role" {
  name        = "tf-assume-readonly-role"
  description = "Allow to assume the readonly-role"
  policy      = "${data.aws_iam_policy_document.assume-readonly-role.json}"
}

// Groups bindings

resource "aws_iam_group_policy_attachment" "attach-readonly-to-unprivileged-group" {
  group      = "${aws_iam_group.unprivileged-group.name}"
  policy_arn = "${aws_iam_policy.assume-readonly-role.arn}"
}

resource "aws_iam_group_policy_attachment" "attach-readonly-to-admin-group" {
  group      = "${aws_iam_group.admin-group.name}"
  policy_arn = "${aws_iam_policy.assume-readonly-role.arn}"
}

### PROD ACCOUNT ###

resource "aws_iam_role" "prod_list_s3" {
  name = "s3-list-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Effect    = "Allow",
        Action    = "sts:AssumeRole",
        Principal = { "AWS" : "arn:aws:iam::${data.aws_caller_identity.utils.account_id}:root" }
    }]
  })
