# IAM Instance Profile
# cf. https://registry.terraform.io/providers/hashicorp/aws/latest/docs/resources/iam_instance_profile
# Use an instance profile to pass an IAM role to an EC2 instance
# cf. 
resource "aws_iam_instance_profile" "cluster_node_profile" {
  name = var.cluster_node_role_name
  role = aws_iam_role.cluster_node_role.name
}

locals {
  context_subject_prefix = var.context == null ? null : {
    environment = "environment:"
    branch      = "ref:refs/heads/"
    tag         = "ref:refs/tags/"
  }

  contexts = (
    var.context == null
    ? ["*"]
    : var.context.type == "pull_request" ? ["pull_request"]
    : [for v in var.context.values : "${local.context_subject_prefix[var.context.type]}${v}"]
  )
}

resource "aws_iam_role" "this" {
  name        = var.iam_role_name_prefix == null ? coalesce(var.iam_role_name, "github-actions-${md5(data.aws_iam_policy_document.this.json)}") : null
  name_prefix = var.iam_role_name_prefix

  assume_role_policy   = data.aws_iam_policy_document.this.json
  max_session_duration = var.max_session_duration

  tags = merge(var.default_tags, var.iam_role_tags)
}

data "aws_iam_policy_document" "this" {
  statement {
    principals {
      type        = "Federated"
      identifiers = [var.iam_openid_connect_provider.arn]
    }

    actions = ["sts:AssumeRoleWithWebIdentity"]

    condition {
      variable = "token.actions.githubusercontent.com:aud"
      test     = "StringEquals"
      values   = [var.openid_audience]
    }

    condition {
      variable = "token.actions.githubusercontent.com:sub"
      test     = "StringLike"
      values = [
        for c in local.contexts : "repo:${var.github_repository.full_name}:${c}"
      ]
    }
  }
}

data "aws_iam_policy_document" "this" {
  statement {
    actions = ["sts:AssumeRole"]

    principals {
      type        = "Service"
      identifiers = ["ec2.amazonaws.com"]
    }
  }
}

resource "aws_iam_role" "this" {
  name                  = "${var.name}"
  assume_role_policy    = "${var.assume_role_policy == "" ? data.aws_iam_policy_document.this.json : var.assume_role_policy}"
  force_detach_policies = "${var.force_detach_policies}"
  path                  = "${var.path}"
  description           = "${var.description}"
}

resource "aws_iam_instance_profile" "this" {
  name       = "${format("%s-%s", var.name, "instance-profile")}"
  path       = "${var.path}"
  role       = "${aws_iam_role.this.name}"
  depends_on = ["aws_iam_role.this"]
}

resource "aws_iam_role_policy_attachment" "this" {
  count      = "${length(var.policy_arn)}"
  role       = "${aws_iam_role.this.name}"
  policy_arn = "${var.policy_arn[count.index]}"
}

data "template_file" "ops_manager" {
  template = "${file("${path.module}/templates/iam_policy.json")}"

  vars {
    iam_instance_profile_arn = "${aws_iam_instance_profile.ops_manager.arn}"
    ops_manager_bucket_arn   = "${aws_s3_bucket.ops_manager_bucket.arn}"
    iam_ops_manager_role_arn = "${aws_iam_role.ops_manager.arn}"
  }
}

data "aws_iam_policy_document" "ops_manager" {
  source_json = "${data.template_file.ops_manager.rendered}"

  statement {
    sid     = "AllowToCreateInstanceWithCurrentInstanceProfile"
    effect  = "Allow"
    actions = ["iam:PassRole"]

    resources = [
      "${compact(concat(list(aws_iam_role.ops_manager.arn), var.additional_iam_roles_arn))}",
    ]
  }
}

resource "aws_iam_policy" "ops_manager_role" {
  name   = "${var.env_name}_ops_manager_role"
  policy = "${data.aws_iam_policy_document.ops_manager.json}"
}

resource "aws_iam_role_policy_attachment" "ops_manager_policy" {
  role       = "${aws_iam_role.ops_manager.name}"
  policy_arn = "${aws_iam_policy.ops_manager_role.arn}"
}

resource "aws_iam_policy" "ops_manager_user" {
  name   = "${var.env_name}_ops_manager_user"
  policy = "${data.aws_iam_policy_document.ops_manager.json}"
}

resource "aws_iam_role" "ops_manager" {
  name = "${var.env_name}_om_role"

  lifecycle {
    create_before_destroy = true
  }

  assume_role_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Principal": {
        "Service": [
          "ec2.amazonaws.com"
        ]
      },
      "Action": [
        "sts:AssumeRole"
      ]
    }
  ]
}
EOF
}

resource "aws_iam_instance_profile" "ops_manager" {
  name = "${var.env_name}_ops_manager"
  role = "${aws_iam_role.ops_manager.name}"

  lifecycle {
    ignore_changes = ["name"]
  }
}

# Backup

data "template_file" "pas_backup_bucket_policy" {
  template = "${file("${path.module}/templates/iam_pas_backup_buckets_policy.json")}"

  vars {
    buildpacks_backup_bucket_arn = "${aws_s3_bucket.buildpacks_backup_bucket.arn}"
    droplets_backup_bucket_arn   = "${aws_s3_bucket.droplets_backup_bucket.arn}"
    packages_backup_bucket_arn   = "${aws_s3_bucket.packages_backup_bucket.arn}"
    resources_backup_bucket_arn  = "${aws_s3_bucket.resources_backup_bucket.arn}"
  }

  count = "${var.create_backup_pas_buckets ? 1 : 0}"
}

resource "aws_iam_policy" "pas_backup_bucket_policy" {
  name   = "${var.env_name}_pas_backup_bucket_policy"
  policy = "${data.template_file.pas_backup_bucket_policy.rendered}"

  count = "${var.create_backup_pas_buckets ? 1 : 0}"
}

resource "aws_iam_role_policy" "pas_backup_bucket_access" {
  name   = "${var.env_name}_pas_backup_bucket_access"
  role   = "${aws_iam_role.pas_bucket_access.id}"
  policy = "${data.template_file.pas_backup_bucket_policy.rendered}"

  count = "${var.create_backup_pas_buckets ? 1 : 0}"
}

resource "aws_iam_user_policy_attachment" "pas_backup_bucket_access" {
  user       = "${var.ops_manager_iam_user_name}"
  policy_arn = "${element(aws_iam_policy.pas_backup_bucket_policy.*.arn, 0)}"

  count = "${var.create_backup_pas_buckets ? 1 : 0}"
}

# ERT

resource "aws_iam_policy" "ert" {
  name   = "${var.env_name}_ert"
  policy = "${data.template_file.ert.rendered}"
}

resource "aws_iam_user_policy_attachment" "ert" {
  user       = "${var.ops_manager_iam_user_name}"
  policy_arn = "${aws_iam_policy.ert.arn}"
}

resource "aws_kms_key" "blobstore_kms_key" {
  description             = "${var.env_name} KMS key"
  deletion_window_in_days = 7

  tags = "${merge(var.tags, map("Name", "${var.env_name} Blobstore KMS Key"))}"
}

resource "aws_kms_alias" "blobstore_kms_key_alias" {
  name          = "alias/${var.env_name}"
  target_key_id = "${aws_kms_key.blobstore_kms_key.key_id}"
}

data "template_file" "ert" {
  template = "${file("${path.module}/templates/iam_pas_buckets_policy.json")}"

  vars {
    buildpacks_bucket_arn = "${aws_s3_bucket.buildpacks_bucket.arn}"
    droplets_bucket_arn   = "${aws_s3_bucket.droplets_bucket.arn}"
    packages_bucket_arn   = "${aws_s3_bucket.packages_bucket.arn}"
    resources_bucket_arn  = "${aws_s3_bucket.resources_bucket.arn}"
    kms_key_arn           = "${aws_kms_key.blobstore_kms_key.arn}"
  }
}

resource "aws_iam_role" "pas_bucket_access" {
  name = "${var.env_name}_pas_bucket_access"

  assume_role_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Action": "sts:AssumeRole",
      "Effect": "Allow",
      "Principal": {
        "Service": "ec2.amazonaws.com"
      }
    }
  ]
}
EOF
}

resource "aws_iam_instance_profile" "pas_bucket_access" {
  name = "${var.env_name}_pas_bucket_access"
  role = "${aws_iam_role.pas_bucket_access.name}"
}

resource "aws_iam_role_policy" "pas_bucket_access" {
  name = "${var.env_name}_pas_bucket_access"
  role = "${aws_iam_role.pas_bucket_access.id}"

  policy = "${data.template_file.ert.rendered}"
}

resource "aws_iam_role_policy_attachment" "pas" {
  role       = "${var.iam_ops_manager_role_name}"
