resource "aws_iam_role_policy_attachment" "eks-AmazonEC2ContainerRegistryReadOnly" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEC2ContainerRegistryReadOnly"
  role       = aws_iam_role.eks_nodegroup_role.name
  }

resource "aws_iam_role" "irsa_iam_role" {
  name = "irsa-iam-role"

  # Terraform's "jsonencode" function converts a Terraform expression result to valid JSON syntax.
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRoleWithWebIdentity"
        Effect = "Allow"
        Sid    = ""
        Principal = {
          Federated = "${aws_iam_openid_connect_provider.oidc_provider.arn }"
        }
        Condition = {
          StringEquals = {            
            "${local.aws_iam_oidc_connect_provider_extract_from_arn}:sub": "system:serviceaccount:default:irsa-demo-sa"
          }
        }        

      },
    ]
  })

}

# Associate IAM Role and Policy
resource "aws_iam_role_policy_attachment" "irsa_iam_role_policy_attach" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3ReadOnlyAccess"
  role       = aws_iam_role.irsa_iam_role.name
}

output "irsa_iam_role_arn" {
  description = "IRSA Demo IAM Role ARN"
  value = aws_iam_role.irsa_iam_role.arn
}

##
# Terraform to build IAM policies, roles, trusts
##

# Define terraform provider
terraform {}

# Download any stable version in AWS provider of 2.19.0 or higher in 2.19 train
provider "aws" {
  region              = "us-east-1"
  version             = "~> 2.20.0"
}

# Creates an IAM role for local ec2 builder to connect as
resource "aws_iam_role" "ado_iam_implicit_role" {
  name = "AzureDevOpsImplicitIamRole"

  assume_role_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Principal": {
        "Service": "ec2.amazonaws.com"
      },
      "Action": "sts:AssumeRole"
    }
  ]
}
EOF

  lifecycle {
    prevent_destroy = true
  }
}

# Create IAM policy to give implicit role permission to assume broad IAM Role
resource "aws_iam_policy" "ado_iam_role_permit_sts_assume" {
  name = "AzureDevOpsPolicyPermitStsAssume"

  policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Action": "sts:AssumeRole",
      "Resource": "${aws_iam_role.ado_iam_assumed_role.arn}"
    }
  ]
}
EOF

  lifecycle {
    prevent_destroy = true
  }
}

# Attach IAM assume role to policy
resource "aws_iam_role_policy_attachment" "ado_iam_attach_implicit_role_to_sts_assume_policy" {
  role       = "${aws_iam_role.ado_iam_implicit_role.name}"
  policy_arn = "${aws_iam_policy.ado_iam_role_permit_sts_assume.arn}"
  lifecycle {
    prevent_destroy = true
  }
}

# Create IAM instance profile so ec2 can associate to it
resource "aws_iam_instance_profile" "ado_iam_role_implicit_instance_profile" {
  name = "AzureDevOpsImplicitIamRole"
  role = "${aws_iam_role.ado_iam_implicit_role.name}"
}

# Create IAM role for ADO builder to assume
resource "aws_iam_role" "ado_iam_assumed_role" {
  name = "AzureDevOpsAssumedIamRole"

  assume_role_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Principal": {
        "AWS": "${aws_iam_role.ado_iam_implicit_role.arn}"
      },
      "Action": "sts:AssumeRole"
    }
  ]
}
EOF

  lifecycle {
    prevent_destroy = true
  }
}

# Create broad IAM policy ADO to use to build, modify resources
resource "aws_iam_policy" "ado_iam_assumed_policy" {
  name = "AzureDevOpsAssumedIamPolicy"

  policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Sid": "AllowAllPermissions",
      "Effect": "Allow",
      "Action": [
        "*"
      ],
      "Resource": "*"
    }
  ]
}
EOF
  lifecycle {
    prevent_destroy = true
  }
}

# Attach IAM assume role to policy
resource "aws_iam_role_policy_attachment" "ado_iam_attach_assumed_role_to_permissions_policy" {
  role       = "${aws_iam_role.ado_iam_assumed_role.name}"
  policy_arn = "${aws_iam_policy.ado_iam_assumed_policy.arn}"
  lifecycle {
    prevent_destroy = true
  }
}

# The ECS Task role permissions
resource "aws_iam_role" "task_role" {
  name               = "${local.service_name_full}-task-role"
  assume_role_policy = data.aws_iam_policy_document.document.json
}

# The ECS Task Execution role IAM permissions
resource "aws_iam_role" "execution_role" {
  name               = "${local.service_name_full}-execution-role"
  assume_role_policy = data.aws_iam_policy_document.document.json
}

resource "aws_iam_role_policy" "execution_role" {
  name = "${local.service_name_full}-execution-role"
  role = aws_iam_role.execution_role.id

  policy = file(local.task.task_execution_role)
}

# Policy document (used by both)
data "aws_iam_policy_document" "document" {
  statement {
    actions = ["sts:AssumeRole"]

    principals {
      identifiers = ["ecs-tasks.amazonaws.com"]
      type        = "Service"
    }
  }
}

/**
 * ## Usage
 *
 * Creates an IAM Role for reading from any Kinesis stream in the account.
 *
 * ```hcl
 * module "kinesis_iam_role" {
 *   source = "dod-iac/kinesis-iam-role/aws"
 *
 *   name = "kinesis-iam-role"
 *   streams = ["*"]
 *   tags = {
 *     Automation  = "Terraform"
 *   }
 * }
 * ```
 *
 * Creates an IAM Role for reading from a specific Kinesis stream.
 *
 * ```hcl
 *
 * module "kinesis_iam_role" {
 *   source = "dod-iac/kinesis-iam-role/aws"
 *
 *   name = format("app-%s-kinesis-%s", var.application, var.environment)
 *   streams = [module.stream.arn]
 *   tags = {
 *     Application = var.application
 *     environment = var.environment
 *     Automation  = "Terraform"
 *   }
 * }
 * ```
 *
 * Creates an IAM Role for allowing another AWS account to read from a specific Kinesis stream.
 *
 * ```hcl
 * data "aws_iam_policy_document" "assume_role_policy" {
 *   statement {
 *     effect  = "Allow"
 *     actions = ["sts:AssumeRole"]
 *     principals {
 *       type = "AWS"
 *       identifiers = [
 *         format("arn:%s:iam::%s:root", data.aws_partition.current.partition, var.consumer_account_id)
 *       ]
 *     }
 *   }
 * }
 *
 * module "kinesis_iam_role" {
 *   source = "dod-iac/kinesis-iam-role/aws"
 *
 *   name = format("app-%s-kinesis-%s", var.application, var.environment)
 *   assume_role_policy = data.aws_iam_policy_document.assume_role_policy.json
 *   streams = [module.stream.arn]
 *   tags = {
 *     Application = var.application
 *     environment = var.environment
 *     Automation  = "Terraform"
 *   }
 * }
 * ```
 *
 * ## Terraform Version
 *
 * Terraform 0.13. Pin module version to ~> 1.0.0 . Submit pull-requests to master branch.
 *
 * Terraform 0.11 and 0.12 are not supported.
 *
 * ## License
 *
 * This project constitutes a work of the United States Government and is not subject to domestic copyright protection under 17 USC § 105.  However, because the project utilizes code licensed from contributors and other third parties, it therefore is licensed under the MIT License.  See LICENSE file for more information.
 */

data "aws_caller_identity" "current" {}

data "aws_partition" "current" {}

data "aws_region" "current" {}

data "aws_iam_policy_document" "assume_role_policy" {
  statement {
    effect  = "Allow"
    actions = ["sts:AssumeRole"]
    principals {
      type = "AWS"
      identifiers = [
        format("arn:%s:iam::%s:root", data.aws_partition.current.partition, data.aws_caller_identity.current.account_id)
      ]
    }
  }
}

resource "aws_iam_role" "main" {
  name               = var.name
  assume_role_policy = length(var.assume_role_policy) > 0 ? var.assume_role_policy : data.aws_iam_policy_document.assume_role_policy.json
  tags               = var.tags
}

data "aws_iam_policy_document" "main" {
  statement {
    sid = "ReadInputStream"
    actions = [
      "kinesis:DescribeStream",
      "kinesis:GetRecords",
      "kinesis:GetShardIterator",
      "kinesis:ListShards"
    ]
    effect    = "Allow"
    resources = var.streams
  }
}

resource "aws_iam_policy" "main" {
  name   = format("%s-policy", var.name)
  path   = "/"
  policy = data.aws_iam_policy_document.main.json
}

resource "aws_iam_role_policy_attachment" "main" {
  role       = aws_iam_role.main.name
  policy_arn = aws_iam_policy.main.arn
}

module "admin_label" {
  source     = "git::https://github.com/cloudposse/terraform-null-label.git?ref=tags/0.3.3"
  namespace  = var.namespace
  stage      = var.stage
  name       = var.admin_name
  delimiter  = var.delimiter
  attributes = var.attributes
  tags       = var.tags
}

module "readonly_label" {
  source     = "git::https://github.com/cloudposse/terraform-null-label.git?ref=tags/0.3.3"
  namespace  = var.namespace
  stage      = var.stage
  name       = var.readonly_name
  delimiter  = var.delimiter
  attributes = var.attributes
  tags       = var.tags
}

data "aws_caller_identity" "current" {}

data "aws_iam_policy_document" "role_trust" {
  count = local.enabled ? 1 : 0

  statement {
    actions = ["sts:AssumeRole"]

    principals {
      type        = "AWS"
      identifiers = ["arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"]
    }

    condition {
      test     = "Bool"
      variable = "aws:MultiFactorAuthPresent"
      values   = ["true"]
    }
  }
}

data "aws_iam_policy_document" "manage_mfa" {
  count = local.enabled ? 1 : 0

  statement {
    sid = "AllowUsersToCreateEnableResyncTheirOwnVirtualMFADevice"

    actions = [
      "iam:CreateVirtualMFADevice",
      "iam:EnableMFADevice",
      "iam:ResyncMFADevice",
    ]

    resources = [
      "arn:aws:iam::${data.aws_caller_identity.current.account_id}:mfa/&{aws:username}",
      "arn:aws:iam::${data.aws_caller_identity.current.account_id}:user/&{aws:username}",
    ]
  }

  statement {
    sid = "AllowUsersToDeactivateTheirOwnVirtualMFADevice"

    actions = [
      "iam:DeactivateMFADevice",
    ]

    resources = [
      "arn:aws:iam::${data.aws_caller_identity.current.account_id}:mfa/&{aws:username}",
      "arn:aws:iam::${data.aws_caller_identity.current.account_id}:user/&{aws:username}",
    ]

    condition {
      test     = "Bool"
      variable = "aws:MultiFactorAuthPresent"
      values   = ["true"]
    }
  }

  statement {
    sid = "AllowUsersToDeleteTheirOwnVirtualMFADevice"

    actions = [
      "iam:DeleteVirtualMFADevice",
    ]

    resources = [
      "arn:aws:iam::${data.aws_caller_identity.current.account_id}:mfa/&{aws:username}",
      "arn:aws:iam::${data.aws_caller_identity.current.account_id}:user/&{aws:username}",
    ]

    condition {
      test     = "Bool"
      variable = "aws:MultiFactorAuthPresent"
      values   = ["true"]
    }
  }

  statement {
    sid = "AllowUsersToListMFADevicesandUsersForConsole"

    actions = [
      "iam:ListMFADevices",
      "iam:ListVirtualMFADevices",
      "iam:ListUsers",
    ]

    resources = [
      "*",
    ]
  }
}

data "aws_iam_policy_document" "allow_change_password" {
  count = local.enabled ? 1 : 0

  statement {
    actions = ["iam:ChangePassword"]

    resources = ["arn:aws:iam::${data.aws_caller_identity.current.account_id}:user/&{aws:username}"]
  }

  statement {
    actions   = ["iam:GetAccountPasswordPolicy"]
    resources = ["*"]
  }

  statement {
    actions = ["iam:GetLoginProfile"]

    resources = ["arn:aws:iam::${data.aws_caller_identity.current.account_id}:user/&{aws:username}"]

    condition {
      test     = "Bool"
      variable = "aws:MultiFactorAuthPresent"
      values   = ["true"]
    }
  }
}

data "aws_iam_policy_document" "allow_key_management" {
  statement {
    actions = [
      "iam:DeleteAccessKey",
      "iam:GetAccessKeyLastUsed",
      "iam:UpdateAccessKey",
      "iam:GetUser",
      "iam:CreateAccessKey",
      "iam:ListAccessKeys",
    ]

    resources = ["arn:aws:iam::${data.aws_caller_identity.current.account_id}:user/&{aws:username}"]

    condition {
      test     = "Bool"
      variable = "aws:MultiFactorAuthPresent"
      values   = ["true"]
    }
  }
}

# Admin config

locals {
  enabled             = var.enabled == "true" ? true : false
  admin_user_names    = length(var.admin_user_names) > 0 ? true : false
  readonly_user_names = length(var.readonly_user_names) > 0 ? true : false
}

resource "aws_iam_policy" "manage_mfa_admin" {
  count       = local.enabled ? 1 : 0
  name        = "${module.admin_label.id}-permit-mfa"
  description = "Allow admin users to manage Virtual MFA Devices"
  policy      = join("", data.aws_iam_policy_document.manage_mfa.*.json)
}

resource "aws_iam_policy" "allow_change_password_admin" {
  count       = local.enabled ? 1 : 0
  name        = "${module.admin_label.id}-permit-change-password"
  description = "Allow admin users to change password"
  policy      = join("", data.aws_iam_policy_document.allow_change_password.*.json)
}

resource "aws_iam_policy" "allow_key_management_admin" {
  name        = "${module.admin_label.id}-allow-key-management"
  description = "Allow admin users to manage their own access keys"
  policy      = data.aws_iam_policy_document.allow_key_management.json
}

data "aws_iam_policy_document" "assume_role_admin" {
  count = local.enabled ? 1 : 0

  statement {
    actions   = ["sts:AssumeRole"]
    resources = ["${join("", aws_iam_role.admin.*.arn)}"]
  }
}

resource "aws_iam_policy" "assume_role_admin" {
  count       = local.enabled ? 1 : 0
  name        = "${module.admin_label.id}-permit-assume-role"
  description = "Allow assuming admin role"
  policy      = join("", data.aws_iam_policy_document.assume_role_admin.*.json)
}

resource "aws_iam_group" "admin" {
  count = local.enabled ? 1 : 0
  name  = module.admin_label.id
}

resource "aws_iam_role" "admin" {
  count              = local.enabled ? 1 : 0
  name               = module.admin_label.id
  assume_role_policy = join("", data.aws_iam_policy_document.role_trust.*.json)
}

resource "aws_iam_group_policy_attachment" "assume_role_admin" {
  count      = local.enabled ? 1 : 0
  group      = join("", aws_iam_group.admin.*.name)
  policy_arn = join("", aws_iam_policy.assume_role_admin.*.arn)
}

resource "aws_iam_group_policy_attachment" "manage_mfa_admin" {
  count      = local.enabled ? 1 : 0
  group      = join("", aws_iam_group.admin.*.name)
  policy_arn = join("", aws_iam_policy.manage_mfa_admin.*.arn)
}

resource "aws_iam_group_policy_attachment" "allow_chage_password_admin" {
  count      = local.enabled ? 1 : 0
  group      = join("", aws_iam_group.admin.*.name)
  policy_arn = join("", aws_iam_policy.allow_change_password_admin.*.arn)
}

resource "aws_iam_group_policy_attachment" "key_management_admin" {
  group      = aws_iam_group.admin.name
  policy_arn = aws_iam_policy.allow_key_management_admin.arn
}

resource "aws_iam_role_policy_attachment" "admin" {
  count      = local.enabled ? 1 : 0
  role       = join("", aws_iam_role.admin.*.name)
  policy_arn = "arn:aws:iam::aws:policy/AdministratorAccess"
}

resource "aws_iam_group_membership" "admin" {
  count = local.enabled && local.admin_user_names ? 1 : 0
  name  = module.admin_label.id
  group = join("", aws_iam_group.admin.*.id)
  users = ["${var.admin_user_names}"]
}

# Readonly config

resource "aws_iam_policy" "manage_mfa_readonly" {
  count       = local.enabled ? 1 : 0
  name        = "${module.readonly_label.id}-permit-mfa"
  description = "Allow readonly users to manage Virtual MFA Devices"
  policy      = join("", data.aws_iam_policy_document.manage_mfa.*.json)
}

resource "aws_iam_policy" "allow_change_password_readonly" {
  count       = local.enabled ? 1 : 0
  name        = "${module.readonly_label.id}-permit-change-password"
  description = "Allow readonly users to change password"
  policy      = join("", data.aws_iam_policy_document.allow_change_password.*.json)
}

resource "aws_iam_policy" "allow_key_management_readonly" {
  name        = "${module.readonly_label.id}-permit-manage-keys"
  description = "Allow readonly users to manage their own access keys"
  policy      = data.aws_iam_policy_document.allow_key_management.json
}

data "aws_iam_policy_document" "assume_role_readonly" {
  statement {
    actions   = ["sts:AssumeRole"]
    resources = ["${join("", aws_iam_role.readonly.*.arn)}"]
  }
}

resource "aws_iam_policy" "assume_role_readonly" {
  count       = local.enabled ? 1 : 0
  name        = "${module.readonly_label.id}-permit-assume-role"
  description = "Allow assuming readonly role"
  policy      = join("", data.aws_iam_policy_document.assume_role_readonly.*.json)
}

resource "aws_iam_group" "readonly" {
  count = local.enabled ? 1 : 0
  name  = module.readonly_label.id
}

resource "aws_iam_role" "readonly" {
  count              = local.enabled ? 1 : 0
  name               = module.readonly_label.id
  assume_role_policy = join("", data.aws_iam_policy_document.role_trust.*.json)
}

resource "aws_iam_group_policy_attachment" "assume_role_readonly" {
  count      = local.enabled ? 1 : 0
  group      = join("", aws_iam_group.readonly.*.name)
  policy_arn = join("", aws_iam_policy.assume_role_readonly.*.arn)
}

resource "aws_iam_group_policy_attachment" "manage_mfa_readonly" {
  count      = local.enabled ? 1 : 0
  group      = join("", aws_iam_group.readonly.*.name)
  policy_arn = join("", aws_iam_policy.manage_mfa_readonly.*.arn)
}

resource "aws_iam_group_policy_attachment" "allow_change_password_readonly" {
  count      = local.enabled ? 1 : 0
  group      = join("", aws_iam_group.readonly.*.name)
  policy_arn = join("", aws_iam_policy.allow_change_password_readonly.*.arn)
}

resource "aws_iam_group_policy_attachment" "key_management_readonly" {
  group      = aws_iam_group.readonly.name
  policy_arn = aws_iam_policy.allow_key_management_readonly.arn
}

resource "aws_iam_role_policy_attachment" "readonly" {
  count      = local.enabled ? 1 : 0
  role       = join("", aws_iam_role.readonly.*.name)
  policy_arn = "arn:aws:iam::aws:policy/ReadOnlyAccess"
}

resource "aws_iam_group_membership" "readonly" {
  count = local.enabled && local.readonly_user_names ? 1 : 0
  name  = module.readonly_label.id
  group = join("", aws_iam_group.readonly.*.id)
  users = ["${var.readonly_user_names}"]
}

locals {
  role_readonly_name = join("", aws_iam_role.readonly.*.name)
  role_admin_name    = join("", aws_iam_role.admin.*.name)
}

resource "aws_iam_role" "vmimport" {
  name               = var.role_name
  assume_role_policy = <<EOF
{
   "Version": "2012-10-17",
   "Statement": [
      {
         "Effect": "Allow",
         "Principal": { "Service": "vmie.amazonaws.com" },
         "Action": "sts:AssumeRole",
         "Condition": {
            "StringEquals":{
               "sts:Externalid": "vmimport"
            }
         }
      }
   ]
}
EOF


  tags = local.common_tags
}

resource "aws_iam_policy" "vmimport" {
  name        = var.role_name
  description = "Policy for ${var.role_name} role"

  policy = <<EOF
{
   "Version":"2012-10-17",
   "Statement":[
      {
         "Effect":"Allow",
         "Action":[
            "s3:GetBucketLocation",
            "s3:GetObject",
            "s3:ListBucket"
         ],
         "Resource":[
            "arn:${var.partition}:s3:::${var.image_bucket_name}",
            "arn:${var.partition}:s3:::${var.image_bucket_name}/*"
         ]
      },
      {
         "Effect":"Allow",
         "Action":[
            "ec2:ModifySnapshotAttribute",
            "ec2:CopySnapshot",
            "ec2:RegisterImage",
            "ec2:Describe*"
         ],
         "Resource":"*"
      }
   ]
}
EOF

}

resource "aws_iam_role_policy_attachment" "vmimport" {
  role       = aws_iam_role.vmimport.name
  policy_arn = aws_iam_policy.vmimport.arn
}

# Create policies

# S3: Raw data and Staging zone (read and write)
resource "aws_iam_policy" "rw_raw_staging" {
  name        = "rw_raw_and_staging"
  path        = "/"
  description = "Provides read and write permissions in raw data and staging zone"

  policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
      {
          "Effect": "Allow",
          "Action": [
                "s3:GetBucketLocation",
                "s3:ListBucket",
                "s3:GetObject",
                "s3:PutObject"
          ],
          "Resource": ["arn:aws:s3:::raw-data", "arn:aws:s3:::staging-zone"]
      }
  ]
}

EOF
}

