EOF
}

locals {
  managed_policy_arns_map = merge({ for i, a in var.managed_policy_arns : format("_#%v_", i) => a }, var.managed_policy_arns_map)
}

data "aws_iam_policy_document" "assume_role" {
  # if the module is enabled and we don't use a `assume_role_policy` then enable the aws_iam_policy_document datasource
  count = module.this.enabled && var.assume_role_policy == null ? length(keys(var.principals)) : 0

  statement {
    effect  = "Allow"
    actions = var.assume_role_actions

    principals {
      type        = element(keys(var.principals), count.index)
      identifiers = var.principals[element(keys(var.principals), count.index)]
    }

    dynamic "condition" {
      for_each = var.assume_role_conditions
      content {
        test     = condition.value.test
        variable = condition.value.variable
        values   = condition.value.values
      }
    }
  }
}

data "aws_iam_policy_document" "assume_role_aggregated" {
  count                     = module.this.enabled ? 1 : 0
  override_policy_documents = var.assume_role_policy != null ? [var.assume_role_policy] : data.aws_iam_policy_document.assume_role[*].json
}

module "role_name" {
  source          = "cloudposse/label/null"
  version         = "0.25.0"
  id_length_limit = 64
  context         = module.this.context
}

resource "aws_iam_role" "default" {
  count                = module.this.enabled ? 1 : 0
  name                 = var.use_fullname ? module.role_name.id : module.this.name
  assume_role_policy   = one(data.aws_iam_policy_document.assume_role_aggregated[*].json)
  description          = var.role_description
  max_session_duration = var.max_session_duration
  permissions_boundary = var.permissions_boundary
  path                 = var.path
  tags                 = module.this.tags
}

resource "aws_iam_role_policy" "default" {
  count = module.this.enabled && var.policy_document_count > 0 && var.inline_policy_enabled ? 1 : 0

  name = var.policy_name != "" && var.policy_name != null ? var.policy_name : module.this.id
  role = one(aws_iam_role.default[*].name)

  policy = one(data.aws_iam_policy_document.default[*].json)
}

data "aws_iam_policy_document" "default" {
  count                     = module.this.enabled && var.policy_document_count > 0 ? 1 : 0
  override_policy_documents = var.policy_documents
}

resource "aws_iam_policy" "default" {
  count       = module.this.enabled && var.policy_document_count > 0 && !var.inline_policy_enabled ? 1 : 0
  name        = var.policy_name != "" && var.policy_name != null ? var.policy_name : module.this.id
  description = var.policy_description
  policy      = one(data.aws_iam_policy_document.default[*].json)
  path        = var.path
  tags        = module.this.tags
}

resource "aws_iam_role_policy_attachment" "default" {
  count      = module.this.enabled && var.policy_document_count > 0 && !var.inline_policy_enabled ? 1 : 0
  role       = one(aws_iam_role.default[*].name)
  policy_arn = one(aws_iam_policy.default[*].arn)
}

resource "aws_iam_role_policy_attachment" "managed" {
  for_each   = module.this.enabled ? local.managed_policy_arns_map : {}
  role       = one(aws_iam_role.default[*].name)
  policy_arn = each.value
}

resource "aws_iam_instance_profile" "default" {
  count = module.this.enabled && var.instance_profile_enabled ? 1 : 0
  name  = module.this.id
  role  = one(aws_iam_role.default[*].name)
  tags  = module.this.tags
}

output "name" {
  value       = one(aws_iam_role.default[*].name)
  description = "The name of the IAM role created"
}

output "id" {
  value       = one(aws_iam_role.default[*].unique_id)
  description = "The stable and unique string identifying the role"
}

output "arn" {
  value       = one(aws_iam_role.default[*].arn)
  description = "The Amazon Resource Name (ARN) specifying the role"
}

output "policy" {
  value       = one(data.aws_iam_policy_document.default[*].json)
  description = "Role policy document in json format. Outputs always, independent of `enabled` variable"
}

output "instance_profile" {
  value       = one(aws_iam_instance_profile.default[*].name)
  description = "Name of the ec2 profile (if enabled)"
}

locals {
  enabled = module.this.enabled
}

provider "aws" {
  region = var.region
}

module "kms_key" {
  source  = "cloudposse/kms-key/aws"
  version = "0.12.1"

  description             = "Test KMS key"
  deletion_window_in_days = 7
  enable_key_rotation     = false

  context = module.this.context
}

module "bucket" {
  # any version greater than 0.47.0 will require the root module to have required_version >= 1.0 in its versions.tf
  source  = "cloudposse/s3-bucket/aws"
  version = "3.1.2"

  user_enabled                 = false
  versioning_enabled           = false
  force_destroy                = true
  allow_encrypted_uploads_only = true
  sse_algorithm                = "aws:kms"
  kms_master_key_arn           = module.kms_key.key_arn

  context = module.this.context
}

data "aws_iam_policy_document" "resource_full_access" {
  count = local.enabled ? 1 : 0

  statement {
    sid       = "FullAccess"
    effect    = "Allow"
    resources = ["${module.bucket.bucket_arn}/*"]

    actions = [
      "s3:PutObject",
      "s3:PutObjectAcl",
      "s3:GetObject",
      "s3:DeleteObject",
      "s3:ListBucket",
      "s3:ListBucketMultipartUploads",
      "s3:GetBucketLocation",
      "s3:AbortMultipartUpload"
    ]
  }
}

data "aws_iam_policy_document" "base" {
  count = local.enabled ? 1 : 0

  statement {
    sid    = "BaseAccess"
    effect = "Allow"

    actions = [
      "s3:ListBucket",
      "s3:ListBucketVersions"
    ]

    resources = [
      module.bucket.bucket_arn
    ]
  }
}

resource "aws_iam_policy" "base_as_managed" {
  count  = local.enabled ? 1 : 0
  name   = module.this.id
  policy = one(data.aws_iam_policy_document.base[*].json)
}

module "role" {
  source = "../.."

  principals   = var.principals
  use_fullname = var.use_fullname

  policy_documents = [
    one(data.aws_iam_policy_document.resource_full_access[*].json),
    one(data.aws_iam_policy_document.base[*].json),
  ]

  managed_policy_arns_map = {
    "base" = one(aws_iam_policy.base_as_managed[*].arn)
  }

  policy_document_count = 2
  policy_description    = "Test IAM policy"
  role_description      = "Test IAM role"
  inline_policy_enabled = var.inline_policy_enabled

  assume_role_policy = var.assume_role_policy

  context = module.this.context
}

resource "aws_iam_group" "group" {
  name = var.group_name
  path = var.group_path
}

resource "aws_iam_group_policy_attachment" "this" {
  group      = aws_iam_group.group.name
  policy_arn = aws_iam_policy.this.arn
}

resource "aws_iam_group_policy" "role_assumption" {
  name  = "${var.group_name}-role-assumption-policy"
  group = aws_iam_group.group.id

  policy = data.aws_iam_policy_document.role_assumption.json

}

resource "aws_iam_group_policy" "user_self_service" {
  name  = "${var.group_name}-user-self-service-policy"
  group = aws_iam_group.group.id

  policy = data.aws_iam_policy_document.user_self_service_policy.json
}

resource "aws_iam_policy" "this" {
  name        = "${var.group_name}-policy"
  description = "Policy to restrict read only users. This makes it so the read only users can't do some tasks like downloading s3 bucket objects and lambda code."
  policy      = data.aws_iam_policy_document.deny_data_retrieval.json
}

resource "aws_iam_role" "this" {
  name               = "${var.group_name}-role"
  tags               = var.input_tags
  assume_role_policy = data.aws_iam_policy_document.cross_account_assume_role_policy_mfa.json
}

resource "aws_iam_role_policy_attachment" "this" {
  role       = aws_iam_role.this.name
  policy_arn = aws_iam_policy.this.arn
}

data "aws_iam_policy_document" "cross_account_assume_role_policy_mfa" {
  statement {
    effect = "Allow"

    principals {
      type = "AWS"
      identifiers = [
        "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"
      ]
    }

    actions = ["sts:AssumeRole"]

    condition {
      test     = "Bool"
      variable = "aws:MultiFactorAuthPresent"
      values = [
        "true",
      ]
    }
  }
}

#tfsec:ignore:aws-iam-no-policy-wildcards
data "aws_iam_policy_document" "user_self_service_policy" {
  statement {
    sid = "ListUsersAccessWithoutMFA"

    actions = [
      "iam:ListVirtualMFADevices"
    ]

    effect = "Allow"

    resources = [
      "*",
    ]
  }

  statement {
    sid = "SelfServiceAccessWithoutMFA"

    actions = [
      "iam:List*",
      "iam:GetUser",
      "iam:GetAccountPasswordPolicy",
      "iam:ChangePassword",
      "iam:CreateVirtualMFADevice",
      "iam:EnableMFADevice"
    ]

    effect = "Allow"

    resources = [
      "arn:aws:iam::*:user/$${aws:username}",
      "arn:aws:iam::*:mfa/$${aws:username}"
    ]
  }

  statement {
    sid = "SelfServiceAccessWithMFA"

    actions = [
      "iam:Get*",
      "iam:DeleteSSHPublicKey",
      "iam:GetSSHPublicKey",
      "iam:ListSSHPublicKeys",
      "iam:UpdateSSHPublicKey",
      "iam:UploadSSHPublicKey",
      "iam:CreateAccessKey",
      "iam:DeleteAccessKey",
      "iam:UpdateAccessKey",
      "iam:DeleteVirtualMFADevice",
      "iam:DeactivateMFADevice",
      "iam:ResyncMFADevice",
      "iam:UploadSigningCertificate",
      "iam:UpdateSigningCertificate",
      "iam:DeleteSigningCertificate",
      "iam:GenerateServiceLastAccessedDetails"
    ]

    effect = "Allow"

    resources = [
      "arn:aws:iam::*:user/$${aws:username}",
      "arn:aws:iam::*:mfa/$${aws:username}"
    ]

    condition {
      test     = "BoolIfExists"
      variable = "aws:MultiFactorAuthPresent"

      values = [
        "true"
      ]
    }
  }

  statement {
    sid = "DenyAllExceptListedIfNoMFA"

    not_actions = [
      "iam:ListVirtualMFADevices",
      "iam:List*",
      "iam:GetUser",
      "iam:GetAccountPasswordPolicy",
      "iam:EnableMFADevice",
      "iam:CreateVirtualMFADevice",
      "iam:ChangePassword"
    ]

    effect = "Deny"

    resources = [
      "*"
    ]

    condition {
      test     = "BoolIfExists"
      variable = "aws:MultiFactorAuthPresent"

      values = [
        "false"
      ]
    }
  }
}

data "aws_iam_policy_document" "role_assumption" {
  statement {
    sid = "AssumeRole"

    actions = [
      "sts:AssumeRole"
    ]

    effect = "Allow"

    resources = [
      aws_iam_role.this.arn
    ]

    condition {
      test     = "BoolIfExists"
      variable = "aws:MultiFactorAuthPresent"

      values = [
        "true"
      ]
    }
  }
}

#tflint-ignore: terraform_required_providers -- Ignore warning on version constraint
data "aws_iam_policy_document" "deny_data_retrieval" {
  statement {
    sid    = "DenyReadOnlyDataRetrieval"
    effect = "Deny"
    actions = [
      "s3:GetObject",
      "s3:GetObjectVersion",
      "s3:GetObjectVersionForReplication",
      "lambda:GetFunction",
      "workdocs:Get*",
      "workmail:Get*",
      "athena:GetQueryResults*",
    ]
    not_resources = var.s3_bucket_paths_to_allow
  }
  statement {
    sid    = "DenyReadOnlySecrets"
    effect = "Deny"
    actions = [
      "secretsmanager:GetSecretValue",
      "ssm:GetParameter*",
      "ecr:GetAuthorizationToken",
      "ec2:GetPasswordData",
      "redshift:GetClusterCredentials",
      "cognito-identity:GetCredentialsForIdentity",
      "cognito-identity:GetId",
      "cognito-identity:GetOpenIdToken",
    ]
    resources = [
      "*",
    ]
  }
}

# Provider configuration for AWS
provider "aws" {
  region = var.aws_region # Dynamically set the region from a variable
  profile = var.aws_profile # Uses a specific AWS profile from your configuration
}

# Provider for generating random strings
provider "random" {}

# Fetch current AWS account details
data "aws_caller_identity" "current" {}

# Generate a random string for creating unique names
resource "random_string" "random" {
  length  = 8
  special = false
  upper   = false
}

# Package the Lambda function code into a ZIP file
data "archive_file" "lambda" {
  type        = "zip"
  source_file = "${path.module}/lambda_function.py"
  output_path = "${path.module}/lambda_function_payload.zip"
}

# IAM role for Lambda function with a unique name
resource "aws_iam_role" "lambda_execution_role" {
  name = "lambda_execution_role-${random_string.random.result}"

  # IAM policy that allows the Lambda function to assume this role
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      },
    ]
  })
}

# IAM policy attached to the Lambda role
resource "aws_iam_role_policy" "lambda_policy" {
  name = "lambda_policy-${random_string.random.result}"
  role = aws_iam_role.lambda_execution_role.id

  # Policy definitions for logging and IAM access
  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ],
        Effect = "Allow",
        Resource = "arn:aws:logs:${var.aws_region}:${data.aws_caller_identity.current.account_id}:log-group:/aws/lambda/${aws_lambda_function.iam_access_key_deactivator.function_name}:*"
      },
      {
        Action = [
          "iam:UpdateAccessKey",
          "iam:ListAccessKeys"
        ],
        Effect = "Allow",
        Resource = "*"
      }
    ]
  })
}

# Lambda function resource
resource "aws_lambda_function" "iam_access_key_deactivator" {
  filename         = "lambda_function_payload.zip"
  function_name    = "iam_access_key_deactivator-${random_string.random.result}"
  role             = aws_iam_role.lambda_execution_role.arn
  handler          = "lambda_function.lambda_handler"
  runtime          = "python3.8"

  source_code_hash = filebase64sha256(data.archive_file.lambda.output_path)
}

# CloudWatch Event Rule to trigger Lambda on IAM policy attachments
resource "aws_cloudwatch_event_rule" "iam_policy_attachment" {
  name        = "iam-policy-attachment-${random_string.random.result}"
  description = "Monitors IAM policy attachments."

  event_pattern = jsonencode({
    source      = ["aws.iam"]
    "detail-type" = ["AWS API Call via CloudTrail"]
    detail = {
      eventName = ["AttachUserPolicy", "AttachGroupPolicy"]
      requestParameters = {
        policyArn = ["arn:aws:iam::aws:policy/AWSCompromisedKeyQuarantineV2"]
      }
    }
  })
}

# Event target that invokes the Lambda function when the event rule triggers
resource "aws_cloudwatch_event_target" "invoke_lambda" {
  rule      = aws_cloudwatch_event_rule.iam_policy_attachment.name
  target_id = "invokeLambdaFunction"
  arn       = aws_lambda_function.iam_access_key_deactivator.arn
}

# Permission for EventBridge (CloudWatch Events) to invoke the Lambda function
resource "aws_lambda_permission" "allow_eventbridge" {
  statement_id  = "AllowExecutionFromEventBridge"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.iam_access_key_deactivator.function_name
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.iam_policy_attachment.arn
}

# CloudWatch Log Group for the Lambda function logs
resource "aws_cloudwatch_log_group" "lambda_log_group" {
  name = "/aws/lambda/${aws_lambda_function.iam_access_key_deactivator.function_name}"

  retention_in_days = 7

  lifecycle {
    prevent_destroy = false
  }
}

data "aws_caller_identity" "current" {}
data "aws_partition" "current" {}

locals {
  account_id = var.aws_account_id == null ? data.aws_caller_identity.current.account_id : var.aws_account_id
  partition  = data.aws_partition.current.partition

  default_role_description = "IAM role for Kubernetes SA ${var.kubernetes_namespace}:${var.kubernetes_service_account_name}"
  role_description_final   = coalesce(var.role_description, local.default_role_description)

  should_create_inline_policy = var.create_role && var.inline_policy_document_json != null
}

resource "null_resource" "validation" {
  count = var.create_role ? 1 : 0

  lifecycle {
    precondition {
      condition     = !local.should_create_inline_policy || (local.should_create_inline_policy && var.inline_policy_name != null)
      error_message = "Configuration error: If 'inline_policy_document_json' is provided and 'create_role' is true, 'inline_policy_name' must also be specified."
    }
  }
}
data "aws_iam_policy_document" "k8s_assume_role_policy" {
  statement {
    actions = ["sts:AssumeRoleWithWebIdentity"]
    effect  = "Allow"

    principals {
      type        = "Federated"
      identifiers = ["arn:${local.partition}:iam::${local.account_id}:oidc-provider/${var.eks_oidc_provider_url}"]
    }

    # :sub condition (Subject - the service account)
    condition {
      test     = "StringEquals"
      variable = "${var.eks_oidc_provider_url}:sub"
      values   = ["system:serviceaccount:${var.kubernetes_namespace}:${var.kubernetes_service_account_name}"]
    }

    # Conditional :aud condition (Audience - sts.amazonaws.com)
    dynamic "condition" {
      for_each = var.add_oidc_aud_condition ? [
        { # Using a list of one map to construct the dynamic block
          test     = "StringEquals"
          variable = "${var.eks_oidc_provider_url}:aud"
          values   = ["sts.amazonaws.com"] # Standard audience for EKS IRSA
        }
      ] : [] # Empty list if condition should not be added

      content {
        test     = condition.value.test
        variable = condition.value.variable
        values   = condition.value.values
      }
    }
  }
}
resource "aws_iam_role" "this" {
  count = var.create_role ? 1 : 0

  name               = var.role_name
  assume_role_policy = data.aws_iam_policy_document.k8s_assume_role_policy.json
  description        = local.role_description_final
  tags               = var.tags

  depends_on = [null_resource.validation]
}

resource "aws_iam_role_policy" "this" {
  count = local.should_create_inline_policy ? 1 : 0

  name   = var.inline_policy_name
  role   = aws_iam_role.this[0].id
  policy = var.inline_policy_document_json
}

resource "aws_iam_role_policy_attachment" "this" {
  for_each = var.create_role ? var.existing_policy_attachments_map : {}

  role       = aws_iam_role.this[0].name
  policy_arn = each.value
}

resource "aws_iam_policy" "this" {
  name        = "example-policy"
  description = "Custom policy to allow access to S3 "

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "aws"
        Effect = "Allow"
        Action = [
          "s3:ListBucket",
          "s3:PutObject",
          "s3:GetObject",
          "s3:DeleteObject"
        ]
        Resource = [
          "arn:aws:s3:::example-bucket",
          "arn:aws:s3:::example-bucket/*",
        ]
      }
    ]
  })
}

locals {
  temp_file_assumerole = var.temp_file_assumerole == "" ? "${path.module}/AssumeRoleService.json.tpl" : var.temp_file_assumerole 
  temp_file_policy     = var.temp_file_policy == "" ? "${path.module}/Policy.json.tpl" : var.temp_file_policy 
}

data "template_file" "assume_role" {
  count    = var.enabled ? 1 : 0
  template = file(local.temp_file_assumerole)
  vars {
    identifiers = jsonencode(var.identifiers)
  }
}

data "template_file" "inline" {
  count    = var.inline_policy && var.enabled ? 1 : 0
  template = file(local.temp_file_policy)
  vars {
    resources = jsonencode(var.resources)
  }
}

resource "aws_iam_role" "this" {
  count = var.enabled ? 1 : 0
  name  = local.name
  path  = var.path
  tags  = var.tags
  description        = var.description
  assume_role_policy = data.template_file.assume_role.rendered
}

resource "aws_iam_role_policy_attachment" "arn" {
  count      = var.enabled ? length(var.policy_arns) : 0
  role       = aws_iam_role.this[0].name
  policy_arn = element(var.policy_arns,count.index)
}

resource "aws_iam_role_policy" "inline" {
  count  = var.inline_policy && var.enabled ? 1 : 0
  name   = var.inline_policy_name == "" ? local.name : var.inline_policy_name
  role   = aws_iam_role.this.id
  policy = data.template_file.inline.rendered
}

resource "aws_iam_instance_profile" "ec2" {
  count = contains(var.identifiers, "ec2.amazonaws.com") && var.enabled ? 1 : 0
  name  = var.name
  role  = aws_iam_role.this[0].name
}

resource "aws_iam_role" "ec2_role" {
  name = "ec2-s3-readonly-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action    = "sts:AssumeRole"
      Effect    = "Allow"
      Principal = {
        Service = "ec2.amazonaws.com"
      }
    }]
  })
}

resource "aws_iam_policy" "s3_readonly" {
  name   = "S3ReadOnlyPolicy"
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action   = ["s3:GetObject","s3:ListBucket"]
      Effect   = "Allow"
      Resource = [
        "arn:aws:s3:::${var.s3_bucket_name}",
        "arn:aws:s3:::${var.s3_bucket_name}/*"
      ]
    }]
  })
}

resource "aws_iam_role_policy_attachment" "attach" {
  role       = aws_iam_role.ec2_role.name
  policy_arn = aws_iam_policy.s3_readonly.arn
}

resource "aws_iam_instance_profile" "ec2_profile" {
  name = "ec2_instance_profile"
  role = aws_iam_role.ec2_role.name
}

data "aws_caller_identity" "current" {
  provider = aws
}

data "aws_iam_policy_document" "default_assume_role" {
  count = var.enabled ? 1 : 0
  statement {
    effect = "Allow"

    principals {
      type        = "AWS"
      identifiers = ["arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"]
    }

    actions = ["sts:AssumeRole"]
  }
}

provider "aws" {
  region = "eu-west-1"
}

locals {
  name        = "role-test"
  environment = "test"
}

##-----------------------------------------------------------------------------
## IAM role module call.
##-----------------------------------------------------------------------------
module "iam-role" {
  source             = "./../../"
  name               = local.name
  environment        = local.environment
  assume_role_policy = data.aws_iam_policy_document.default.json
  policy_enabled     = true
  policy             = data.aws_iam_policy_document.iam-policy.json
  managed_policy_arns = [
    "arn:aws:iam::aws:policy/AmazonS3ReadOnlyAccess",
  ]
}

##-----------------------------------------------------------------------------
## Data block to create IAM policy.
##-----------------------------------------------------------------------------
data "aws_iam_policy_document" "default" {
  statement {
    effect  = "Allow"
    actions = ["sts:AssumeRole"]
    principals {
      type        = "Service"
      identifiers = ["ec2.amazonaws.com"]
    }
  }
}

##-----------------------------------------------------------------------------
## Data block to create IAM policy.
##-----------------------------------------------------------------------------
data "aws_iam_policy_document" "iam-policy" {
  statement {
    actions = [
      "ssm:UpdateInstanceInformation",
      "ssmmessages:CreateControlChannel",
      "ssmmessages:CreateDataChannel",
      "ssmmessages:OpenControlChannel",
    "ssmmessages:OpenDataChannel"]
    effect    = "Allow"
    resources = ["*"]
  }
}

##-----------------------------------------------------------------------------
## Labels module callled that will be used for naming and tags.
##-----------------------------------------------------------------------------
module "labels" {
  source  = "clouddrove/labels/aws"
  version = "1.3.0"

  name        = var.name
  repository  = var.repository
  environment = var.environment
  managedby   = var.managedby
  label_order = var.label_order
}

##-----------------------------------------------------------------------------
## Data block to tls certificate.
##-----------------------------------------------------------------------------

data "tls_certificate" "github" {
  url = var.provider_url
}

##-----------------------------------------------------------------------------
## Data block for openid connect provider
##-----------------------------------------------------------------------------

data "aws_iam_openid_connect_provider" "github" {
  count = var.oidc_provider_exists ? 1 : 0
  url   = var.provider_url
}

##-----------------------------------------------------------------------------
## Include iam openid connect provider resource here
##-----------------------------------------------------------------------------


resource "aws_iam_openid_connect_provider" "github" {
  count           = var.oidc_provider_exists ? 0 : 1
  client_id_list  = ["sts.amazonaws.com"]
  thumbprint_list = length(var.oidc_thumbprint_list) > 0 ? var.oidc_thumbprint_list : (var.oidc_provider_exists ? [] : [data.tls_certificate.github.certificates[0].sha1_fingerprint])
  url             = var.provider_url
  tags            = module.labels.tags
}

##-----------------------------------------------------------------------------
## Include the role resource and attachment here
##-----------------------------------------------------------------------------

resource "aws_iam_role" "github" {
  name = var.role_name
  tags = module.labels.tags
  assume_role_policy = var.custom_assume_role_policy != "" ? var.custom_assume_role_policy : jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Effect = "Allow",
        Principal = {
          Federated = var.oidc_provider_exists ? data.aws_iam_openid_connect_provider.github[0].arn : aws_iam_openid_connect_provider.github[0].arn

        },
        Action = "sts:AssumeRoleWithWebIdentity",
        Condition = {
          StringEquals = {
            "token.actions.githubusercontent.com:aud" = "sts.amazonaws.com"
          },
          "ForAnyValue:StringLike" = {
            "token.actions.githubusercontent.com:sub" = [
              for repo in var.oidc_github_repos : "repo:${repo}:*"
            ]
          }
        }

      }
    ]
  })
}

##-----------------------------------------------------------------------------
## Include the iam role policy resource attachment here
##-----------------------------------------------------------------------------

resource "aws_iam_role_policy_attachment" "github" {
  count      = length(var.policy_arns)
  role       = aws_iam_role.github.name
  policy_arn = var.policy_arns[count.index]
}

/**
 * ## Usage
 *
 * Creates an IAM Role for use as a SageMaker service role that can use any KMS key.
 *
 * ```hcl
 * module "sagemaker_iam_role" {
 *   source = "dod-iac/sagemaker-iam-role/aws"
 *
 *   name = "sagemaker-iam-role"
 *   keys = ["*"]
 *   tags = {
 *     Automation  = "Terraform"
 *   }
 * }
 * ```
 *
 * ## Terraform Version
 *
 * Terraform 0.13. Pin module version to ~> 1.0.0 . Submit pull-requests to main branch.
 *
 * Terraform 0.11 and 0.12 are not supported.
 *
