 *
 * This project constitutes a work of the United States Government and is not subject to domestic copyright protection under 17 USC § 105.  However, because the project utilizes code licensed from contributors and other third parties, it therefore is licensed under the MIT License.  See LICENSE file for more information.
 */

data "aws_partition" "current" {}

data "aws_iam_policy_document" "assume_role_policy" {
  statement {
    effect  = "Allow"
    actions = ["sts:AssumeRole"]
    principals {
      type = "Service"
      identifiers = [
        "sagemaker.amazonaws.com"
      ]
    }
  }
}

resource "aws_iam_role" "main" {
  name               = var.name
  description        = var.description
  assume_role_policy = length(var.assume_role_policy) > 0 ? var.assume_role_policy : data.aws_iam_policy_document.assume_role_policy.json
  tags               = var.tags
}

resource "aws_iam_role_policy_attachment" "aws_sagemaker_service_role" {
  role       = aws_iam_role.main.name
  policy_arn = format("arn:%s:iam::aws:policy/AmazonSageMakerFullAccess", data.aws_partition.current.partition)
}

data "aws_iam_policy_document" "main" {

  statement {
    sid = "Decrypt"
    actions = [
      "kms:Decrypt",
    ]
    effect    = length(var.keys) > 0 ? "Allow" : "Deny"
    resources = length(var.keys) > 0 ? var.keys : ["*"]
  }

}

resource "aws_iam_policy" "main" {
  name        = length(var.policy_name) > 0 ? var.policy_name : format("%s-policy", var.name)
  description = length(var.policy_description) > 0 ? var.policy_description : format("The policy for %s.", var.name)
  policy      = data.aws_iam_policy_document.main.json
}

resource "aws_iam_role_policy_attachment" "main" {
  role       = aws_iam_role.main.name
  policy_arn = aws_iam_policy.main.arn
}

# EKS OIDC / IRSA support for IAM roles
# Allows Kubernetes service accounts to assume this IAM role

variable "eks_oidc_provider_enabled" {
  type        = bool
  description = "Enable EKS OIDC provider for IRSA (IAM Roles for Service Accounts)"
  default     = false
}

variable "eks_oidc_provider_arn" {
  type        = string
  description = <<-EOT
    ARN of the EKS OIDC provider. Required when eks_oidc_provider_enabled is true.
    Format: arn:aws:iam::<account-id>:oidc-provider/oidc.eks.<region>.amazonaws.com/id/<cluster-id>
    EOT
  default     = ""

  validation {
    condition     = !var.eks_oidc_provider_enabled || var.eks_oidc_provider_arn != ""
    error_message = "eks_oidc_provider_arn must be set if EKS OIDC provider is enabled"
  }
}

variable "eks_oidc_issuer_url" {
  type        = string
  description = <<-EOT
    The OIDC issuer URL from the EKS cluster (without https:// prefix).
    Format: oidc.eks.<region>.amazonaws.com/id/<cluster-id>
    If not specified, it will be derived from eks_oidc_provider_arn.
    EOT
  default     = ""
}

variable "eks_oidc_audience" {
  type        = list(string)
  description = <<-EOT
    The expected `aud` (audience) claims on OIDC tokens presented when assuming this role.
    Defaults to `["sts.amazonaws.com"]`, which is what AWS-managed EKS clusters use for IRSA.
    Foreign OIDC providers (third-party SaaS vendors whose EKS cluster federates into
    this account) may mint tokens with a different, vendor-specific audience — set this
    to match the `aud` claim(s) they issue. A list is accepted to support trust policies
    that need to accept tokens from multiple audiences (e.g., during an audience migration).
    EOT
  default     = ["sts.amazonaws.com"]
}

variable "service_account_name" {
  type        = string
  description = <<-EOT
    The name of the Kubernetes service account allowed to assume this role.
    Use '*' to allow any service account in the namespace.
    Defaults to module.this.name if not specified.
    EOT
  default     = null
}

variable "service_account_namespace" {
  type        = string
  description = <<-EOT
    The Kubernetes namespace of the service account allowed to assume this role.
    Defaults to module.this.name if not specified.
    EOT
  default     = null
}

locals {
  eks_oidc_enabled = local.enabled && var.eks_oidc_provider_enabled

  # Default service account namespace and name to module.this.name if not specified.
  # Only evaluated when eks_oidc_enabled is true, which guarantees module.this.name is non-empty.
  # coalesce() returns the first non-null, non-empty argument.
  service_account_namespace = local.eks_oidc_enabled ? coalesce(var.service_account_namespace, module.this.name) : ""
  service_account_name      = local.eks_oidc_enabled ? coalesce(var.service_account_name, module.this.name) : ""

  # Extract OIDC issuer URL from ARN if not explicitly provided
  # ARN format: arn:aws:iam::<account-id>:oidc-provider/<issuer-url>
  eks_oidc_issuer_url = local.eks_oidc_enabled ? coalesce(
    var.eks_oidc_issuer_url,
    try(regex("oidc-provider/(.+)$", var.eks_oidc_provider_arn)[0], "")
  ) : ""

  # Construct the subject claim for the service account
  # Format: system:serviceaccount:<namespace>:<service-account-name>
  eks_service_account_subject = local.eks_oidc_enabled ? "system:serviceaccount:${local.service_account_namespace}:${local.service_account_name}" : ""
}

data "aws_iam_policy_document" "eks_oidc_provider_assume" {
  count = local.eks_oidc_enabled ? 1 : 0

  statement {
    sid = "EksOidcProviderAssume"
    actions = [
      "sts:AssumeRoleWithWebIdentity",
      "sts:TagSession",
    ]

    principals {
      type        = "Federated"
      identifiers = [var.eks_oidc_provider_arn]
    }

    # Verify the audience claim matches what the OIDC provider issues
    # (defaults to `sts.amazonaws.com` for AWS-managed EKS / IRSA)
    condition {
      test     = "StringEquals"
      variable = "${local.eks_oidc_issuer_url}:aud"
      values   = var.eks_oidc_audience
    }

    # Restrict to specific namespace and service account
    # Use StringLike to support wildcards in service account name
    condition {
      test     = local.service_account_name == "*" ? "StringLike" : "StringEquals"
      variable = "${local.eks_oidc_issuer_url}:sub"
      values   = [local.eks_service_account_subject]
    }
  }
}

output "eks_assume_role_policy" {
  value       = local.eks_oidc_enabled ? one(data.aws_iam_policy_document.eks_oidc_provider_assume[*].json) : null
  description = "JSON encoded string representing the EKS OIDC \"Assume Role\" policy"
}

output "eks_oidc_provider_arn" {
  value       = local.eks_oidc_enabled ? var.eks_oidc_provider_arn : null
  description = "ARN of the EKS OIDC provider (pass-through for reference)"
}

output "eks_service_account_subject" {
  value       = local.eks_service_account_subject
  description = "The service account subject claim used in the trust policy"
}

variable "github_oidc_provider_enabled" {
  type        = bool
  description = "Enable GitHub OIDC provider"
  default     = false
}

variable "trusted_github_repos" {
  type        = list(string)
  description = <<-EOT
    A list of GitHub repositories allowed to access this role.
    Format is either "orgName/repoName" or just "repoName",
    in which case "cloudposse" will be used for the "orgName".
    Wildcard ("*") is allowed for "repoName".
    EOT
  default     = []
}

variable "trusted_github_org" {
  type        = string
  description = "The GitHub organization unqualified repos are assumed to belong to. Keeps `*` from meaning all orgs and all repos."
  default     = ""
}

variable "github_oidc_provider_arn" {
  type        = string
  description = "ARN of the GitHub OIDC provider"
  default     = ""

  validation {
    condition     = !local.github_oidc_enabled || var.github_oidc_provider_arn != ""
    error_message = "github_oidc_provider_arn must be set if GitHub OIDC provider is enabled"
  }
}

locals {
  github_oidc_enabled = local.enabled && var.github_oidc_provider_enabled && length(var.trusted_github_repos) > 0

  trusted_github_repos_regexp = "^(?:(?P<org>[^://]*)\\/)?(?P<repo>[^://]*):?(?P<constraint>.*)?$"
  trusted_github_repos_sub    = [for r in var.trusted_github_repos : regex(local.trusted_github_repos_regexp, r)]

  github_repos_sub = [
    for r in local.trusted_github_repos_sub : (
      r["constraint"] == "" ?
      format("repo:%s/%s:*", coalesce(r["org"], var.trusted_github_org), r["repo"]) :
      startswith(r["constraint"], "ref:") || startswith(r["constraint"], "environment:") ?
      format("repo:%s/%s:%s", coalesce(r["org"], var.trusted_github_org), r["repo"], r["constraint"]) :
      format("repo:%s/%s:ref:refs/heads/%s", coalesce(r["org"], var.trusted_github_org), r["repo"], r["constraint"])
    )
  ]
}

data "aws_iam_policy_document" "github_oidc_provider_assume" {
  count = local.github_oidc_enabled ? 1 : 0

  statement {
    sid = "OidcProviderAssume"
    actions = [
      "sts:AssumeRoleWithWebIdentity",
      "sts:SetSourceIdentity",
      "sts:TagSession",
    ]

    principals {
      type = "Federated"

      identifiers = [var.github_oidc_provider_arn]
    }

    condition {
      test     = "StringEquals"
      variable = "token.actions.githubusercontent.com:aud"
      values   = ["sts.amazonaws.com"]
    }

    condition {
      test     = "StringLike"
      variable = "token.actions.githubusercontent.com:sub"

      values = local.github_repos_sub
    }
  }
}

output "github_assume_role_policy" {
  value       = local.github_oidc_enabled ? one(data.aws_iam_policy_document.github_oidc_provider_assume[*].json) : null
  description = "JSON encoded string representing the \"Assume Role\" policy configured by the inputs"
}

locals {
  enabled = module.this.enabled

  # Convert policy_statements to a single policy document
  # Normalize the structure to match IAM policy document format (capitalized keys)
  # Combine all statements into one policy document
  policy_document_from_statements = length(var.policy_statements) > 0 ? {
    Version = "2012-10-17"
    Statement = [
      for sid, stmt in var.policy_statements : merge(
        {
          # Map lowercase YAML keys to capitalized IAM policy keys
          for k, v in {
            Sid          = sid
            Effect       = stmt.effect
            Action       = stmt.actions
            NotAction    = stmt.not_actions
            Principal    = stmt.principal
            NotPrincipal = stmt.not_principal
            Condition    = stmt.condition
            Resource     = stmt.resources
            NotResource  = stmt.not_resources
          } : k => v if v != null
        }
      )
    ]
  } : null

  # Convert the single policy document to JSON string
  policy_document_from_statements_json = local.policy_document_from_statements != null ? jsonencode(local.policy_document_from_statements) : null

  # Merge policy_documents (JSON strings) with the single policy document from statements
  all_policy_documents = compact(concat(
    var.policy_documents,
    local.policy_document_from_statements_json != null ? [local.policy_document_from_statements_json] : []
  ))

  # Automatically set policy_document_count to 0 if all_policy_documents is empty
  # This prevents creating an invalid IAM policy with only a Version field
  policy_document_count = length(local.all_policy_documents) > 0 ? length(local.all_policy_documents) : 0
}

data "aws_iam_policy_document" "assume_role_policy" {
  count = local.enabled && (var.assume_role_policy != null || local.github_oidc_enabled || local.eks_oidc_enabled) ? 1 : 0

  # Merge assume_role_policy with GitHub OIDC and EKS OIDC policies if they exist
  source_policy_documents = compact([
    var.assume_role_policy,
    try(one(data.aws_iam_policy_document.github_oidc_provider_assume[*].json), null),
    try(one(data.aws_iam_policy_document.eks_oidc_provider_assume[*].json), null)
  ])
}

module "role" {
  source  = "cloudposse/iam-role/aws"
  version = "0.23.0"

  assume_role_policy       = var.assume_role_policy != null || local.github_oidc_enabled || local.eks_oidc_enabled ? one(data.aws_iam_policy_document.assume_role_policy[*].json) : null
  assume_role_actions      = var.assume_role_actions
  assume_role_conditions   = var.assume_role_conditions
  instance_profile_enabled = var.instance_profile_enabled
  managed_policy_arns      = var.managed_policy_arns
  max_session_duration     = var.max_session_duration
  path                     = var.path
  permissions_boundary     = var.permissions_boundary
  policy_description       = var.policy_description
  policy_document_count    = local.policy_document_count
  policy_documents         = local.all_policy_documents
  policy_name              = var.policy_name
  principals               = var.principals
  role_description         = var.role_description
  use_fullname             = var.use_fullname

  context = module.this.context
}

#####################################################################
#
# Data source, build block statement 
# for Assume Role Policy
data "aws_iam_policy_document" "assume_role_policy" {
    dynamic "statement" {
        for_each = var.assume_role_policy

        content {
            sid         = lookup(statement.value, "sid", null)
            effect      = lookup(statement.value, "effect", null)
            actions     = lookup(statement.value, "actions", null)
            resources   = lookup(statement.value, "resources", null)

        dynamic "condition" {
          for_each = length(keys(lookup(statement.value, "condition", {}))) == 0 ? [] : [lookup(statement.value, "condition", {})]
          content {
            test      = lookup(condition.value, "test", null)
            variable  = lookup(condition.value, "variable", null)
            values    = lookup(condition.value, "values", null)

          }
        }

        dynamic "principals" {
          for_each = length(keys(lookup(statement.value, "principals", {}))) == 0 ? [] : [lookup(statement.value, "principals", {})]
          content {
            type        = lookup(principals.value, "type", null)
            identifiers = lookup(principals.value, "identifiers", null)
          }
        }
      }
    }
}
#####################################################################
#
# IAM Role
resource "aws_iam_role" "main" {
    count = var.create ? 1 : 0

    name        = var.name
    path        = var.path
    description = var.description

    assume_role_policy    = data.aws_iam_policy_document.assume_role_policy.json
    force_detach_policies = var.force_detach_policies
    max_session_duration  = var.max_session_duration

    tags    = var.default_tags
}
#####################################################################
#
# IAM Role Policy Attachment
resource "aws_iam_role_policy_attachment" "main" {
  count = var.create ? length(var.import_managed_policies) : 0

  role       = aws_iam_role.main.0.id
  policy_arn = lookup(var.import_managed_policies[count.index], "policies_arn", null)
}
#####################################################################
#
# Data source, build block statement 
# for IAM Policy
data "aws_iam_policy_document" "policy_document" {
    count   = var.create ? length(var.iam_policy) : 0

    dynamic "statement" {
        for_each = var.iam_policy

        content {
            sid         = lookup(statement.value, "sid", null)
            effect      = lookup(statement.value, "effect", null)
            actions     = lookup(statement.value, "actions", null)
            not_actions = lookup(statement.value, "not_actions", null)
            resources   = lookup(statement.value, "resources", null)

        dynamic "condition" {
          for_each = length(keys(lookup(statement.value, "condition", {}))) == 0 ? [] : [lookup(statement.value, "condition", {})]
          content {
            test      = lookup(condition.value, "test", null)
            variable  = lookup(condition.value, "variable", null)
            values    = lookup(condition.value, "values", null)

          }
        }

        dynamic "principals" {
          for_each = length(keys(lookup(statement.value, "principals", {}))) == 0 ? [] : [lookup(statement.value, "principals", {})]
          content {
            type        = lookup(principals.value, "type", null)
            identifiers = lookup(principals.value, "identifiers", null)
          }
        }
      }
    }
}
#####################################################################
#
# IAM Role Policy
resource "aws_iam_role_policy" "main" {
    count   = var.create ? 1 : 0

    name      = length(var.iam_policy) > 1 || var.use_num_suffix ? format("%s-%d", "${var.name}-Policy", count.index + 1) : "${var.name}-Policy"
    role      = aws_iam_role.main.0.id
    policy    = element(data.aws_iam_policy_document.policy_document[*].json, count.index)
}

resource "aws_iam_instance_profile" "this" {
  name = var.name
  role = aws_iam_role.this.name
  path = var.path
}

resource "aws_iam_role" "this" {
  name                  = var.name
  path                  = var.path
  description           = var.description
  force_detach_policies = var.force_detach_policies
  assume_role_policy    = data.aws_iam_policy_document.this.json
}

data "aws_iam_policy_document" "this" {
  statement {
    actions = ["sts:AssumeRole"]

    principals {
      type        = "Service"
      identifiers = ["ec2.amazonaws.com"]
    }
  }
}

resource "aws_iam_role_policy_attachment" "this" {
  count      = length(var.policy_arn)
  role       = aws_iam_role.this.name
  policy_arn = var.policy_arn[count.index]
  depends_on = [var.depend_on]
}

resource "aws_iam_role" "flow_log_role" {
  name = var.flow_log_role_name

  assume_role_policy = <<EOF
{
    "Version": "2012-10-17",
    "Statement": [
        {
            "Effect": "Allow",
            "Principal": {
                "Service": "vpc-flow-logs.amazonaws.com"
            },
            "Action": "sts:AssumeRole"
        }
    ]
}
EOF
}

resource "aws_iam_role_policy" "vpc_flow_log_policy" {
  role   = aws_iam_role.flow_log_role.name
  policy = <<EOF
{
    "Version": "2012-10-17",
    "Statement": [
        {
            "Effect": "Allow",
            "Action": [
                "logs:CreateLogGroup",
                "logs:CreateLogStream",
                "logs:PutLogEvents",
                "logs:DescribeLogGroups",
                "logs:DescribeLogStreams"
            ],
            "Resource": "*"
