}
EOF
}

# AWS Support Access Role for Access to AWS Support
resource "aws_iam_role" "aws_support_role" {
  name = var.aws_support_role_name

  assume_role_policy = <<EOF
{
    "Version": "2012-10-17",
    "Statement": [
        {
            "Effect": "Allow",
            "Principal": {
                "AWS": "arn:aws:iam::${var.account_id}:root"
            },
            "Action": "sts:AssumeRole",
            "Condition": {}
        }
    ]
}
EOF
}

resource "aws_iam_role_policy_attachment" "aws_support_role_policy_attachment" {
  role       = aws_iam_role.aws_support_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSSupportAccess"
}

/* ADD Roles as per requirement
resource "aws_iam_role" "role_name" {
  name = var.role_name

  assume_role_policy = <<EOF

  EOF
}

resource "aws_iam_role_policy" "policy" {
  role   = aws_iam_role.role.name
  policy = <<EOF

EOF
}
*/

locals {
    policy_arns = flatten([
        for role_name, role in var.assumeRoles: [
            for policy_key, policy_arns in role.attach_policy_arns: {
                role_name = role_name
                policy_key = policy_key
                policy_arns = policy_arns
            }
        ]
    ])

    inline_policies = flatten([
        for role_name, role in var.assumeRoles: [
            for policy_key, inline_policy in role.inline_policies: {
                role_name = role_name
                policy_key = policy_key
                inline_policy = inline_policy
            }
        ]
    ])
}

data "aws_iam_policy_document" "role-document" {    
    for_each = var.assumeRoles
    policy_id = each.key
    statement {
        effect = "Allow"
        actions = ["sts:AssumeRole"]
        principals {
            type = "AWS"
            identifiers = each.value.trusted_arns
        }
    }
}

resource aws_iam_role assume_role {
    for_each = var.assumeRoles
    name = each.key
    description = each.value.description
    assume_role_policy = data.aws_iam_policy_document.role-document[each.key].json
}

resource aws_iam_role_policy_attachment "policy_attachments" {
    for_each = {
        for policy in local.policy_arns : "${policy.role_name}.${policy.policy_key}" => policy
    }
    role = aws_iam_role.assume_role[each.value.role_name].name
    policy_arn = each.value.policy_arns
}

resource "aws_iam_role_policy" "inline_policy" {
    for_each = {
          for policy in local.inline_policies : "${policy.role_name}.${policy.policy_key}" => policy
    }
    name = each.value.policy_key
    role = aws_iam_role.assume_role[each.value.role_name].name
    policy = each.value.inline_policy
}

data "aws_partition" "current" {}

locals {
  # This is the Lucid's AWS import proxy account. It is used to assume the role to do AWS imports. 799803075172 for commercial and 239369393023 for govcloud
  import_proxy_account_id = data.aws_partition.current.partition == "aws-us-gov" ? "239369393023" : "799803075172"
}

data "aws_iam_policy_document" "bastion_assume_role_policy" {
  statement {
    effect  = "Allow"
    actions = ["sts:AssumeRole"]
    principals {
      type        = "AWS"
      identifiers = ["arn:${data.aws_partition.current.partition}:iam::${local.import_proxy_account_id}:root"]
