## eks_iam

variable "iam_role_enabled" {
  type        = bool
  description = "Whether to create an IAM role. Setting this to `true` will also replace any occurrences of `{service_account_role_arn}` in `var.values_template_path` with the ARN of the IAM role created by this module."
  default     = false
}

## eks_iam_policy

variable "iam_policy_enabled" {
  type        = bool
  description = "Whether to create and attach an IAM policy to the created IAM role"
  default     = true
}

variable "iam_source_policy_documents" {
  type        = list(string)
  description = <<-EOT
    List of IAM policy documents (as JSON strings) that are merged together into the exported document.
    Statements defined in `iam_source_policy_documents` must have unique SIDs and be distinct from SIDs
    in `iam_policy` and deprecated `iam_policy_statements`.
    Statements in these documents will be overridden by statements with the same SID in `iam_override_policy_documents`.
    EOT
  default     = null
}

variable "iam_override_policy_documents" {
  type        = list(string)
  description = <<-EOT
    List of IAM policy documents (as JSON strings) that are merged together into the exported document with higher precedence.
    In merging, statements with non-blank SIDs will override statements with the same SID
    from earlier documents in the list and from other "source" documents.
    EOT
  default     = null
}

variable "iam_source_json_url" {
  type        = string
  description = <<-EOT
    URL of the IAM policy (in JSON format) to download and use as `source_json` argument.
    This is useful when using a 3rd party service that provides their own policy.
    Statements in this policy will be overridden by statements with the same SID in `iam_override_policy_documents`.
    EOT
  default     = null
}

variable "iam_policy_statements" {
  type        = any
  description = <<-EOT
    Deprecated: Use `iam_policy` instead.
    List or Map of IAM policy statements to use in the policy.
    This can be used with `iam_source_policy_documents` and `iam_override_policy_documents`
    and with or instead of `iam_source_json_url`.
    EOT
  default     = {}
}

variable "iam_policy" {
  type = list(object({
    policy_id = optional(string, null)
    version   = optional(string, null)
    statements = list(object({
      sid           = optional(string, null)
      effect        = optional(string, null)
      actions       = optional(list(string), null)
      not_actions   = optional(list(string), null)
      resources     = optional(list(string), null)
      not_resources = optional(list(string), null)
      conditions = optional(list(object({
        test     = string
        variable = string
        values   = list(string)
      })), [])
      principals = optional(list(object({
        type        = string
        identifiers = list(string)
      })), [])
      not_principals = optional(list(object({
        type        = string
        identifiers = list(string)
      })), [])
    }))
  }))
  description = <<-EOT
    IAM policy as list of Terraform objects, compatible with Terraform `aws_iam_policy_document` data source
    except that `source_policy_documents` and `override_policy_documents` are not included.
    Use inputs `iam_source_policy_documents` and `iam_override_policy_documents` for that.
    EOT
  default     = null
}

## eks_iam_role

variable "aws_account_number" {
  type        = string
  description = "AWS account number of EKS cluster owner."
  default     = null
}

variable "aws_partition" {
  type        = string
  description = "AWS partition: `aws`, `aws-cn`, or `aws-us-gov`. Applicable when `var.iam_role_enabled` is `true`."
  default     = "aws"
}

variable "eks_cluster_oidc_issuer_url" {
  type        = string
  description = "OIDC issuer URL for the EKS cluster (initial \"https://\" may be omitted)."

  validation {
    condition     = length(var.eks_cluster_oidc_issuer_url) > 0
    error_message = "The eks_cluster_oidc_issuer_url value must have a value."
  }
}

variable "service_account_role_arn_annotation_enabled" {
  type        = bool
  description = <<-EOT
  Whether or not to dynamically insert an `eks.amazonaws.com/role-arn` annotation into `$var.service_account_set_key_path.annotations`
  (by default, `serviceAccount.annotations`), with the value being the ARN of the IAM role created when `var.iam_role_enabled`.

  Assuming the Helm Chart follows the standard convention of rendering ServiceAccount annotations in `serviceAccount.annotations`
  (or a similar convention, which can be overriden by `var.service_account_set_key_path` as needed),
  this allows the ServiceAccount created by the Helm Chart to assume the IAM Role in question via the EKS OIDC IdP, without
  the consumer of this module having to set this annotation via `var.values` or `var.set`, which would involve manually
  rendering the IAM Role ARN beforehand.

  Ignored if `var.iam_role_enabled` is `false`.
  EOT
  default     = true
}

variable "service_account_set_key_path" {
  type        = string
  description = <<-EOT
  The key path used by Helm Chart values for ServiceAccount-related settings (e.g. `serviceAccount...` or `rbac.serviceAccount...`).

  Ignored if either `var.service_account_role_arn_annotation_enabled` or `var.iam_role_enabled` are set to `false`.
  EOT
  default     = "serviceAccount.annotations.eks\\.amazonaws\\.com/role-arn"
}

variable "service_account_name" {
  type        = string
  description = <<-EOT
  Name of the Kubernetes ServiceAccount allowed to assume the IAM role created when `var.iam_role_enabled` is set to `true`.

  In combination with `var.service_account_namespace`, this variable is used to determine which ServiceAccounts are allowed
  to assume the IAM role in question.

  It is *not* recommended to leave this variable as `null` or `""`, as this would mean ServiceAccounts of any name in the
  namespace specified by `var.service_account_namespace` are allowed to assume the IAM role in question. If both variables
  are omitted, then a ServiceAccount of any name in any namespace will be able to assume the IAM role in question, which
  is the least secure scenario.

  The best practice is to set this variable to the name of the ServiceAccount created by the Helm Chart.
  EOT
  default     = null
}

variable "service_account_namespace" {
  type        = string
  description = <<-EOT
  Kubernetes Namespace of the Kubernetes ServiceAccount allowed to assume the IAM role created when `var.iam_role_enabled`
  is set to `true`.

  In combination with `var.service_account_name`, this variable is used to determine which ServiceAccounts are allowed
  to assume the IAM role in question.

  It is *not* recommended to leave this variable as `null` or `""`, as this would mean any ServiceAccounts matching the
  name specified by `var.service_account_name` in any namespace are allowed to assume the IAM role in question. If both
  variables are omitted, then a ServiceAccount of any name in any namespace will be able to assume the IAM role in question,
  which is the least secure scenario.

  The best practice is to set this variable to the namespace of the ServiceAccount created by the Helm Chart.
  EOT
  default     = null
}

### helm_release

variable "chart" {
  type        = string
  description = "Chart name to be installed. The chart name can be local path, a URL to a chart, or the name of the chart if `repository` is specified. It is also possible to use the `<repository>/<chart>` format here if you are running Terraform on a system that the repository has been added to with `helm repo add` but this is not recommended."
}

variable "release_name" {
  type        = string
  description = "The name of the release to be installed. If omitted, use the name input, and if that's omitted, use the chart input."
  default     = ""
}

variable "description" {
  type        = string
  description = "Release description attribute (visible in the history)."
  default     = null
}

variable "devel" {
  type        = bool
  description = "Use chart development versions, too. Equivalent to version `>0.0.0-0`. If version is set, this is ignored."
  default     = null
}

variable "repository" {
  type        = string
  description = "Repository URL where to locate the requested chart."
  default     = null
}

variable "repository_ca_file" {
  type        = string
  description = "The Repositories CA file."
  default     = null
}

variable "repository_cert_file" {
  type        = string
  description = "The repositories cert file."
  default     = null
}

variable "repository_key_file" {
  type        = string
  description = "The repositories cert key file."
  default     = null
}

variable "repository_password" {
  type        = string
  description = "Password for HTTP basic authentication against the repository."
  default     = null
}

variable "repository_username" {
  type        = string
  description = "Username for HTTP basic authentication against the repository."
  default     = null
}

variable "chart_version" {
  type        = string
  description = "Specify the exact chart version to install. If this is not specified, the latest version is installed."
  default     = null
}

variable "create_namespace" {
  type        = bool
  description = <<-EOT
    (Not recommended, use `create_namespace_with_kubernetes` instead)
    Create the namespace via Helm if it does not yet exist. Defaults to `false`.
    Does not support annotations or labels. May have problems when destroying.
    Ignored when `create_namespace_with_kubernetes` is set.
    EOT
  default     = null
}

variable "create_namespace_with_kubernetes" {
  type        = bool
  description = <<-EOT
    Create the namespace via Kubernetes if it does not yet exist. Defaults to `false`.
    Must set `true` if you want to use namespace annotations or labels.
    EOT
  default     = null
}

variable "kubernetes_namespace" {
  type        = string
  description = "The namespace to install the release into. Defaults to `default`."
  default     = null
}

variable "kubernetes_namespace_annotations" {
  type        = map(string)
  description = "Annotations to be added to the created namespace. Ignored unless `create_namespace_with_kubernetes` is `true`."
  default     = {}
}

variable "kubernetes_namespace_labels" {
  type        = map(string)
  description = "Labels to be added to the created namespace. Ignored unless `create_namespace_with_kubernetes` is `true`."
  default     = {}
}

variable "atomic" {
  type        = bool
  description = "If set, installation process purges chart on fail. The wait flag will be set automatically if atomic is used. Defaults to `false`."
  default     = null
}

variable "cleanup_on_fail" {
  type        = bool
  description = "Allow deletion of new resources created in this upgrade when upgrade fails. Defaults to `false`."
  default     = null
}

variable "dependency_update" {
  type        = bool
  description = "Runs helm dependency update before installing the chart. Defaults to `false`."
  default     = null
}

variable "disable_openapi_validation" {
  type        = bool
  description = "If set, the installation process will not validate rendered templates against the Kubernetes OpenAPI Schema. Defaults to `false`."
  default     = null
}

variable "disable_webhooks" {
  type        = bool
  description = "Prevent hooks from running. Defaults to `false`."
  default     = null
}

variable "force_update" {
  type        = bool
  description = "Force resource update through delete/recreate if needed. Defaults to `false`."
  default     = null
}

variable "keyring" {
  type        = string
  description = "Location of public keys used for verification. Used only if `verify` is true. Defaults to `/.gnupg/pubring.gpg` in the location set by `home`."
  default     = null
}

variable "lint" {
  type        = bool
  description = "Run the helm chart linter during the plan. Defaults to `false`."
  default     = null
}

variable "max_history" {
  type        = number
  description = "Maximum number of release versions stored per release. Defaults to `0` (no limit)."
  default     = null
}

variable "recreate_pods" {
  type        = bool
  description = "Perform pods restart during upgrade/rollback. Defaults to `false`."
  default     = null
}

variable "render_subchart_notes" {
  type        = bool
  description = "If set, render subchart notes along with the parent. Defaults to `true`."
  default     = null
}

variable "replace" {
  type        = bool
  description = "Re-use the given name, even if that name is already used. This is unsafe in production. Defaults to `false`."
  default     = null
}

variable "reset_values" {
  type        = bool
  description = "When upgrading, reset the values to the ones built into the chart. Defaults to `false`."
  default     = null
}

variable "reuse_values" {
  type        = bool
  description = "When upgrading, reuse the last release's values and merge in any overrides. If `reset_values` is specified, this is ignored. Defaults to `false`."
  default     = null
}

variable "skip_crds" {
  type        = bool
  description = "If set, no CRDs will be installed. By default, CRDs are installed if not already present. Defaults to `false`."
  default     = null
}

variable "timeout" {
  type        = number
  description = "Time in seconds to wait for any individual kubernetes operation (like Jobs for hooks). Defaults to `300` seconds."
  default     = null
}

variable "values" {
  type        = any
  description = "List of values in raw yaml to pass to helm. Values will be merged, in order, as Helm does with multiple `-f` options."
  default     = null
}

variable "verify" {
  type        = bool
  description = "Verify the package before installing it. Helm uses a provenance file to verify the integrity of the chart; this must be hosted alongside the chart. For more information see the Helm Documentation. Defaults to `false`."
  default     = null
}

variable "wait" {
  type        = bool
  description = "Will wait until all resources are in a ready state before marking the release as successful. It will wait for as long as `timeout`. Defaults to `true`."
  default     = null
}

variable "wait_for_jobs" {
  type        = bool
  description = "If wait is enabled, will wait until all Jobs have been completed before marking the release as successful. It will wait for as long as `timeout`. Defaults to `false`."
  default     = null
}

variable "set" {
  type = list(object({
    name  = string
    value = string
    type  = string
  }))
  description = "Value block with custom values to be merged with the values yaml."
  default     = []
}

variable "set_sensitive" {
  type = list(object({
    name  = string
    value = string
    type  = string
  }))
  description = "Value block with custom sensitive values to be merged with the values yaml that won't be exposed in the plan's diff."
  default     = []
}

variable "postrender_binary_path" {
  type        = string
  description = "Relative or full path to command binary."
  default     = null
}

variable "permissions_boundary" {
  type        = string
  description = "ARN of the policy that is used to set the permissions boundary for the role."
  default     = null
}

data "aws_iam_policy_document" "assume_role" {
  source_policy_documents = try([var.assume_role_policy.json], [])

  dynamic "statement" {
    for_each = length(var.assume_role_services) > 0 || length(var.assume_role_arns) > 0 ? [1] : []

    content {
      sid = "Module"

      actions = ["sts:AssumeRole"]

      dynamic "principals" {
        for_each = length(var.assume_role_services) > 0 ? [var.assume_role_services] : []

        content {
          type        = "Service"
          identifiers = principals.value
        }
      }

      dynamic "principals" {
        for_each = length(var.assume_role_arns) > 0 ? [var.assume_role_arns] : []

        content {
          type        = "AWS"
          identifiers = principals.value
        }
      }
    }
  }
}

resource "aws_iam_role" "role" {
  path = var.path
  name = var.name

  assume_role_policy    = data.aws_iam_policy_document.assume_role.json
  max_session_duration  = var.max_session_duration
  force_detach_policies = var.force_detach_policies
  description           = var.description
  permissions_boundary  = var.permissions_boundary == "" ? null : var.permissions_boundary
}

resource "aws_iam_role_policy" "access_policy" {
  count = var.access_policy == null ? 0 : (var.wait_for_policy ? 1 : 0)

  name   = "AccessPolicy"
  role   = aws_iam_role.role.name
  policy = var.access_policy.json
}

resource "aws_iam_role_policy" "access_policy_independent" {
  count = var.access_policy == null ? 0 : (var.wait_for_policy ? 0 : 1)

  name   = "AccessPolicy"
  role   = aws_iam_role.role.name
  policy = var.access_policy.json
}

resource "aws_iam_role_policy_attachment" "managed_policies" {
  for_each = var.wait_for_policy ? toset(var.managed_policy_arns) : toset([])

  role       = aws_iam_role.role.name
  policy_arn = each.value
}

resource "aws_iam_role_policy_attachment" "managed_policies_independent" {
  for_each = var.wait_for_policy ? toset([]) : toset(var.managed_policy_arns)

  role       = aws_iam_role.role.name
  policy_arn = each.value
}

resource "aws_iam_instance_profile" "profile" {
  count = var.instance_profile ? 1 : 0

  name = aws_iam_role.role.name
  role = aws_iam_role.role.name
}

# ------------------
# Std Assume Role
# ------------------
data "aws_iam_policy_document" "this" {
  statement {
    actions = ["sts:AssumeRole"]

    principals {
      type        = var.principal_type
      identifiers = var.principal_identifiers
    }
  }
}

locals {

  prefix = format("%s-%s-%s", var.project, var.environment, var.subject)
}

/*
 * Resources
 */

resource "aws_iam_role" "role" {
  name               = format("%s-role", local.prefix)
  assume_role_policy = data.aws_iam_policy_document.assume-role-policy-document.json
  path               = var.path
}

data "aws_iam_policy_document" "assume-role-policy-document" {

  statement {
    effect = "Allow"

    principals {
      identifiers = var.principals
      type = "Service"
    }

    actions = [
      "sts:AssumeRole"
    ]
  }
}

//
// Attach Existing Policies
//

data "aws_iam_policy" "managed-policy" {
  count = length(var.policies)
  arn   = element(var.policies, count.index)
}

resource "aws_iam_role_policy_attachment" "existing-role-policy-attachment" {
  count = length(var.policies)

  policy_arn = element(data.aws_iam_policy.managed-policy.*.arn, count.index)
  role       = aws_iam_role.role.name
}

//
// Create New Custom Policy
//

resource "aws_iam_policy" "policy" {
  count = length(var.actions) > 0 ? 1 : 0

  name        = format("%s-policy", local.prefix)
  path        = "/"
  description = format("%s-policy", local.prefix)
  policy      = data.aws_iam_policy_document.policy-document[0].json
}

data "aws_iam_policy_document" "policy-document" {
  count = length(var.actions) > 0 ? 1 : 0

  statement {

    effect = var.effect
    resources = var.resources
    actions = var.actions

  }
}

resource "aws_iam_role_policy_attachment" "role-policy-attachment" {
  count = length(var.actions) > 0 ? 1 : 0

  policy_arn = aws_iam_policy.policy[0].arn
  role       = aws_iam_role.role.name
}

/**
 * ## Usage
 *
 * Creates an IAM Role for use by AWS API Gateway to log to CloudWatch Logs.
 *
 * ```hcl
 * module "api_gateway_cloudwatch_role" {
 *   source = "dod-iac/api-gateway-cloudwatch-role/aws"
 *
 *   name = "api-gateway-cloudwatch-role"
 *   tags = {
 *     Automation  = "Terraform"
 *   }
 * }
 *
 * resource "aws_api_gateway_account" "main" {
 *   cloudwatch_role_arn = module.api_gateway_cloudwatch_role.arn
 * }
 * ```
 *
 * ## Terraform Version
 *
 * Terraform 0.12. Pin module version to ~> 1.0.0 . Submit pull-requests to master branch.
 *
 * Terraform 0.11 is not supported.
 *
 * ## License
 *
 * This project constitutes a work of the United States Government and is not subject to domestic copyright protection under 17 USC § 105.  However, because the project utilizes code licensed from contributors and other third parties, it therefore is licensed under the MIT License.  See LICENSE file for more information.
 */

data "aws_caller_identity" "current" {}

data "aws_partition" "current" {}

data "aws_region" "current" {}

resource "aws_iam_role" "main" {
  name               = var.name
  assume_role_policy = <<-EOF
  {
    "Version": "2012-10-17",
    "Statement": [
      {
        "Sid": "",
        "Effect": "Allow",
        "Principal": {
          "Service": "apigateway.amazonaws.com"
        },
        "Action": "sts:AssumeRole"
      }
    ]
  }
  EOF
  tags               = var.tags
}

data "aws_iam_policy_document" "main" {
  statement {
    sid = "WelcomeLogGroups"
    actions = [
      "logs:CreateLogGroup",
      "logs:DescribeLogStreams"
    ]
    effect = "Allow"
    resources = [
      format(
        "arn:%s:logs:%s:%s:log-group:/aws/apigateway/welcome:log-stream:",
        data.aws_partition.current.partition,
        data.aws_region.current.name,
        data.aws_caller_identity.current.account_id
      )
    ]
  }
  statement {
    sid = "WelcomeLogStreams"
    actions = [
      "logs:CreateLogStream",
      "logs:PutLogEvents",
    ]
    effect = "Allow"
    resources = [
      format(
        "arn:%s:logs:%s:%s:log-group:/aws/apigateway/welcome:log-stream:*",
        data.aws_partition.current.partition,
        data.aws_region.current.name,
        data.aws_caller_identity.current.account_id
      )
    ]
  }
  statement {
    sid = "LogGroups"
    actions = [
      "logs:CreateLogGroup",
      "logs:DescribeLogGroups",
      "logs:FilterLogEvents"
    ]
    effect = "Allow"
    resources = [
      format(
        "arn:%s:logs:%s:%s:log-group:API-Gateway-Execution-Logs_*",
        data.aws_partition.current.partition,
        data.aws_region.current.name,
        data.aws_caller_identity.current.account_id
      )
    ]
  }
  statement {
    sid = "LogStreams"
    actions = [
      "logs:DescribeLogStreams",
      "logs:CreateLogStream",
      "logs:PutLogEvents",
      "logs:GetLogEvents"
    ]
    effect = "Allow"
    resources = [
      format(
        "arn:%s:logs:%s:%s:log-group:API-Gateway-Execution-Logs_*:log-stream:*",
        data.aws_partition.current.partition,
        data.aws_region.current.name,
        data.aws_caller_identity.current.account_id
      )
    ]
  }
}

resource "aws_iam_policy" "main" {
  name   = format("%s-policy", var.name)
  path   = "/"
  policy = data.aws_iam_policy_document.main.json
}

resource "aws_iam_role_policy_attachment" "main" {
  role       = aws_iam_role.main.name
  policy_arn = aws_iam_policy.main.arn
}

#################################################################################
# Requirements
#################################################################################
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
    }
  }
}
# Declare variables
variable "gcp_sa_display_name" {}
variable "gcp_sa_email" {}
variable "gcp_sa_unique_id" {}
variable "aws_iam_role_name" {
  default = "gcp_aws_federated_role"
}
#################################################################################
# Resources
#################################################################################
resource "aws_iam_role" "gcp_aws_federated_role" {
  name = var.aws_iam_role_name

  # Update this section with the trust policy
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        "Effect": "Allow",
        "Principal": {
          "Federated": "accounts.google.com"
        },
        "Action": "sts:AssumeRoleWithWebIdentity",
        "Condition": {
          "StringEquals": {
            "accounts.google.com:oaud": "GCP_federated_role_${var.aws_iam_role_name}",
            "accounts.google.com:email": var.gcp_sa_email,
            "accounts.google.com:sub": var.gcp_sa_unique_id
          }
        }
      },
      {
        "Effect": "Allow",
        "Principal": {
          "Service": "ec2.amazonaws.com"
        },
        "Action": "sts:AssumeRole"
      }
    ]
  })

  tags = {
    tag-key = "test-tag"
  }
}

# Reference existing AWS IAM policy
data "aws_iam_policy" "AmazonEC2ReadOnlyAccess" {
  arn = "arn:aws:iam::aws:policy/AmazonEC2ReadOnlyAccess"
}
# Assign the existing AWS IAM policy to your new role.
resource "aws_iam_role_policy_attachment" "amazon-readonly-role-policy-attach" {
  role       = "${aws_iam_role.gcp_aws_federated_role.name}"
  policy_arn = "${data.aws_iam_policy.AmazonEC2ReadOnlyAccess.arn}"
}
#################################################################################
# Outputs 
#################################################################################
output "aws_role_name" {
  value = aws_iam_role.gcp_aws_federated_role.name
}

output "aws_role_arn" {
  value = aws_iam_role.gcp_aws_federated_role.arn
}

provider "aws" {
  region = "eu-west-1"
}

##-----------------------------------------------------------------------------
## IAM role module call.
##-----------------------------------------------------------------------------
module "iam-role" {
  source             = "./../../."
  name               = "iam"
  environment        = "test"
  assume_role_policy = data.aws_iam_policy_document.default.json
  policy_enabled     = true
  policy             = data.aws_iam_policy_document.iam-policy.json
}

##-----------------------------------------------------------------------------
## Data block to create IAM policy.
##-----------------------------------------------------------------------------
data "aws_iam_policy_document" "default" {
  statement {
    effect  = "Allow"
    actions = ["sts:AssumeRole"]
    principals {
      type        = "Service"
      identifiers = ["ec2.amazonaws.com"]
    }
  }
}

##-----------------------------------------------------------------------------
## Data block to create IAM policy.
##-----------------------------------------------------------------------------
data "aws_iam_policy_document" "iam-policy" {
  statement {
    actions = [
      "ssm:UpdateInstanceInformation",
      "ssmmessages:CreateControlChannel",
      "ssmmessages:CreateDataChannel",
      "ssmmessages:OpenControlChannel",
    "ssmmessages:OpenDataChannel"]
    effect    = "Allow"
    resources = ["*"]
  }
}

